-- ----------------------------
-- Table structure for advn_ad_income_log_2027
-- ----------------------------
DROP TABLE IF EXISTS `advn_ad_income_log_2027`;
CREATE TABLE `advn_ad_income_log_2027`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `ad_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'feed' COMMENT '广告类型: feed=信息流, reward=激励视频',
  `adpid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '广告位ID',
  `ad_provider` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'uniad' COMMENT '广告平台: uniad=uni-ad, csj=穿山甲, ylh=优量汇',
  `ad_source` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'redbag_page' COMMENT '广告来源页面: redbag_page=红包群, task_page=任务页',
  `amount` decimal(18, 4) NOT NULL DEFAULT 0.0000 COMMENT '广告返回总金额（元）',
  `amount_coin` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '广告返回总金额（金币）',
  `platform_rate` decimal(5, 4) NOT NULL DEFAULT 0.3000 COMMENT '平台抽成比例',
  `platform_amount` decimal(18, 4) NOT NULL DEFAULT 0.0000 COMMENT '平台抽成金额（元）',
  `platform_amount_coin` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '平台抽成金额（金币）',
  `user_amount` decimal(18, 4) NOT NULL DEFAULT 0.0000 COMMENT '用户实际获得金额（元）',
  `user_amount_coin` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户实际获得金币',
  `status` tinyint NOT NULL DEFAULT 0 COMMENT '状态: 0=待确认, 1=已确认, 2=已释放, 3=已失效',
  `transaction_id` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '广告联盟交易ID（防重复回调）',
  `ip` varchar(45) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '回调IP',
  `user_agent` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '用户UA',
  `device_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '设备ID',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '备注',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_ad_type`(`ad_type` ASC) USING BTREE,
  INDEX `idx_adpid`(`adpid` ASC) USING BTREE,
  INDEX `idx_ad_provider`(`ad_provider` ASC) USING BTREE,
  INDEX `idx_transaction_id`(`transaction_id` ASC) USING BTREE,
  INDEX `idx_createtime`(`createtime` ASC) USING BTREE,
  INDEX `idx_user_status`(`user_id` ASC, `status` ASC) USING BTREE,
  INDEX `idx_user_status_createtime`(`user_id` ASC, `status` ASC, `createtime` ASC) USING BTREE,
  INDEX `idx_createtime_status`(`createtime` ASC, `status` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '广告收益记录表' ROW_FORMAT = Dynamic;

