INSERT INTO `advn_admin_log` VALUES (639, 1, 'admin', '/BgYmdTvqpf.php/singlepage/page/edit/ids/1?dialog=1', '单页管理 / 单页管理 / 编辑', '{\"dialog\":\"1\",\"__token__\":\"***\",\"row\":{\"category_id\":\"5\",\"title\":\"欢迎使用\",\"keywords\":\"公告,弹窗,通知\",\"description\":\"首页弹窗公告示例\",\"image\":\"\",\"tpl\":\"\",\"content\":\"欢迎使用本平台感谢您的支持与信任！1、本平台提供丰富多样的短剧内容，观看视频即可获得金币奖励；2、金币可在钱包中申请提现，支持微信自动打款；3、邀请好友加入还可获得额外奖励，多邀多得。—— 系统公告\",\"weigh\":\"100\",\"status\":\"1\"},\"ids\":\"1\"}', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36 Edg/146.0.0.0', 1775034534);
INSERT INTO `advn_admin_log` VALUES (640, 1, 'admin', '/BgYmdTvqpf.php/general.config/edit', '常规管理 / 系统配置 / 编辑', '{\"__token__\":\"***\",\"row\":{\"wechat_app_enabled\":\"1\",\"wechat_app_appid\":\"wx3c078ec2e418ee00\",\"wechat_app_secret\":\"7ca43697e562cc960c4ae64be1b81c7c\",\"wechat_mini_enabled\":\"0\",\"wechat_mini_appid\":\"\",\"wechat_mini_secret\":\"\",\"wechat_official_enabled\":\"1\",\"wechat_official_appid\":\"\",\"wechat_official_secret\":\"\",\"wechat_pay_enabled\":\"0\",\"wechat_pay_mchid\":\"\",\"wechat_pay_key\":\"\",\"wechat_pay_notify_url\":\"\",\"wechat_transfer_enabled\":\"0\",\"wechat_transfer_mchid\":\"\",\"wechat_transfer_key\":\"\",\"wechat_auto_register\":\"1\",\"wechat_bind_mobile\":\"0\"}}', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36 Edg/146.0.0.0', 1775095065);
INSERT INTO `advn_admin_log` VALUES (641, 1, 'admin', '/BgYmdTvqpf.php/singlepage/page/edit/ids/2?dialog=1', '单页管理 / 单页管理 / 编辑', '{\"dialog\":\"1\",\"__token__\":\"***\",\"row\":{\"category_id\":\"6\",\"title\":\"分销规则\",\"keywords\":\"分销规则,分销说明,佣金规则\",\"description\":\"平台分销佣金的规则和说明\",\"image\":\"\",\"tpl\":\"distribution-rules\",\"content\":\"平台分销规则一、分销等级平台分销共设有以下等级，根据累计佣金金额自动升级：等级名称累计佣金要求Lv1普通会员0元Lv2青铜代理100元Lv3白银代理500元Lv4黄金代理2,000元Lv5铂金代理5,000元Lv6钻石代理10,000元Lv7星耀代理50,000元Lv8王者代理100,000元二、佣金规则通过邀请好友注册成为您的下级，当下级在平台产生消费行为时，您可获得相应的佣金奖励：1. 一级佣金（直接邀请）您直接邀请的好友在平台消费（提现、观看视频、领取红包、游戏等），您可获得一定比例的一级佣金奖励。一级佣金比例根据消费类型不同而有所差异，具体以平台公布为准。2. 二级佣金（间接邀请）您直接邀请的好友再邀请其他好友，这些好友产生消费时，您也可获得一定比例的二级佣金奖励。二级佣金比例通常低于一级佣金。三、佣金来源来源类型说明提现分佣下级用户成功提现时，上级获得佣金视频分佣下级用户观看视频产生收益时，上级获得佣金红包分佣下级用户领取红包时，上级获得佣金游戏分佣下级用户参与游戏消费时，上级获得佣金四、佣金结算1. 佣金产生后进入待结算状态，系统将在一定时间后自动结算为可用余额。2. 已结算的佣金将以金币形式发放至您的金币账户，可在钱包中申请提现。3. 提现金额 = 金币余额 ÷ 汇率，具体汇率以平台实时公示为准。五、邀请方式您可以通过以下方式邀请好友：邀请链接：将您的专属邀请链接发送给好友，好友点击链接注册即成为您的下级。邀请码：将您的邀请码告知好友，好友在注册时输入邀请码即可绑定关系。二维码海报：生成专属邀请海报，好友扫码即可注册。六、注意事项每位用户只能绑定一位邀请人（一级），绑定后不可更改。禁止通过虚假交易、刷单等违规方式获取佣金，一经发现将取消佣金并封禁账号。平台有权根据运营情况调整佣金比例和规则，调整前会提前公告。如有疑问请联系客服咨询。—— 平台运营团队\",\"weigh\":\"100\",\"status\":\"1\"},\"ids\":\"2\"}', '127.0.0.1', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/146.0.0.0 Safari/537.36 Edg/146.0.0.0', 1775102548);
