-- ----------------------------
-- Table structure for advn_ban_record
-- ----------------------------
DROP TABLE IF EXISTS `advn_ban_record`;
CREATE TABLE `advn_ban_record`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `ban_type` enum('temporary','permanent') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'temporary' COMMENT '封禁类型',
  `ban_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '封禁原因',
  `ban_source` enum('auto','manual') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'auto' COMMENT '封禁来源',
  `risk_score` int NOT NULL DEFAULT 0 COMMENT '封禁时风险分',
  `rule_codes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '触发的规则编码JSON',
  `admin_id` int UNSIGNED NULL DEFAULT NULL COMMENT '操作管理员ID',
  `admin_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '操作管理员名称',
  `start_time` int UNSIGNED NOT NULL COMMENT '开始时间',
  `end_time` int UNSIGNED NULL DEFAULT NULL COMMENT '结束时间(NULL永久)',
  `duration` int NOT NULL DEFAULT 0 COMMENT '封禁时长(秒,0永久)',
  `status` enum('active','released','expired') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'active' COMMENT '状态',
  `release_time` int UNSIGNED NULL DEFAULT NULL COMMENT '解封时间',
  `release_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '解封原因',
  `release_admin_id` int UNSIGNED NULL DEFAULT NULL COMMENT '解封管理员ID',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_ban_type`(`ban_type` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_start_time`(`start_time` ASC) USING BTREE,
  INDEX `idx_end_time`(`end_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 14 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '封禁记录表' ROW_FORMAT = Dynamic;

