-- ----------------------------
-- Table structure for advn_coin_account
-- ----------------------------
DROP TABLE IF EXISTS `advn_coin_account`;
CREATE TABLE `advn_coin_account`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `balance` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '可用金币余额',
  `frozen` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '冻结金币(提现申请中)',
  `total_earn` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '累计获得金币',
  `total_spend` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '累计消费金币',
  `total_withdraw` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '累计提现金币',
  `today_earn` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '今日获得金币',
  `today_earn_date` date NULL DEFAULT NULL COMMENT '今日统计日期',
  `ad_freeze_balance` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '广告待释放金币（空闲钱包）',
  `total_ad_income` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '累计广告收益（金币）',
  `version` int UNSIGNED NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间戳',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间戳',
  `admin_id` int UNSIGNED NULL DEFAULT NULL COMMENT '创建该记录的管理员ID',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_balance`(`balance` ASC) USING BTREE,
  INDEX `idx_admin_id`(`admin_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 54 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '金币账户表' ROW_FORMAT = Dynamic;

