-- ----------------------------
-- Table structure for advn_daily_commission_stat
-- ----------------------------
DROP TABLE IF EXISTS `advn_daily_commission_stat`;
CREATE TABLE `advn_daily_commission_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '统计ID',
  `date_key` date NOT NULL COMMENT '日期',
  `total_commission` decimal(14, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '总佣金(元)',
  `total_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '总金币',
  `withdraw_commission` decimal(14, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '提现分佣(元)',
  `video_commission` decimal(14, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '视频分佣(元)',
  `red_packet_commission` decimal(14, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '红包分佣(元)',
  `game_commission` decimal(14, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '游戏分佣(元)',
  `total_count` int UNSIGNED NULL DEFAULT 0 COMMENT '总次数',
  `user_count` int UNSIGNED NULL DEFAULT 0 COMMENT '获得佣金用户数',
  `level1_count` int UNSIGNED NULL DEFAULT 0 COMMENT '一级分佣次数',
  `level2_count` int UNSIGNED NULL DEFAULT 0 COMMENT '二级分佣次数',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_date_key`(`date_key` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 32 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '每日佣金统计表' ROW_FORMAT = Dynamic;

