-- ----------------------------
-- Table structure for advn_data_migration_config
-- ----------------------------
DROP TABLE IF EXISTS `advn_data_migration_config`;
CREATE TABLE `advn_data_migration_config`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `table_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '表名',
  `archive_days` int UNSIGNED NULL DEFAULT 90 COMMENT '归档天数',
  `batch_size` int UNSIGNED NULL DEFAULT 1000 COMMENT '批处理数量',
  `delete_source` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否删除源数据',
  `auto_archive` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否自动归档',
  `archive_schedule` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '归档计划(cron表达式)',
  `last_archive_time` int UNSIGNED NULL DEFAULT NULL COMMENT '最后归档时间',
  `last_archive_count` int UNSIGNED NULL DEFAULT 0 COMMENT '最后归档数量',
  `total_archive_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '累计归档数量',
  `enabled` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '是否启用',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_table_name`(`table_name` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '数据迁移配置表' ROW_FORMAT = Dynamic;

