-- ----------------------------
-- Table structure for advn_data_migration_log
-- ----------------------------
DROP TABLE IF EXISTS `advn_data_migration_log`;
CREATE TABLE `advn_data_migration_log`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '日志ID',
  `table_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '表名',
  `action` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作类型: migrate/clean/stats',
  `total_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '总数据量',
  `migrated_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '迁移数量',
  `failed_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '失败数量',
  `deleted_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '删除数量',
  `duration` int UNSIGNED NULL DEFAULT 0 COMMENT '执行时长(秒)',
  `params` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '执行参数JSON',
  `result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '执行结果JSON',
  `error` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '错误信息',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_table_name`(`table_name` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '数据迁移日志表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_data_migration_log
-- ----------------------------

-- ----------------------------
-- Table structure for advn_device_fingerprint
-- ----------------------------
DROP TABLE IF EXISTS `advn_device_fingerprint`;
CREATE TABLE `advn_device_fingerprint`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `device_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '设备唯一标识',
  `device_hash` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '设备特征哈希',
  `user_id` int UNSIGNED NOT NULL COMMENT '绑定用户ID',
  `device_type` enum('ios','android','web','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'other' COMMENT '设备类型',
  `device_brand` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '设备品牌',
  `device_model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '设备型号',
  `os_version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '系统版本',
  `app_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'APP版本',
  `screen_resolution` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '屏幕分辨率',
  `network_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '网络类型',
  `carrier` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '运营商',
  `root_detected` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否检测到Root/越狱',
  `emulator_detected` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否检测到模拟器',
  `hook_detected` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否检测到Hook框架',
  `proxy_detected` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否检测到代理',
  `vpn_detected` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否检测到VPN',
  `risk_score` int NOT NULL DEFAULT 0 COMMENT '设备风险分',
  `risk_level` enum('safe','suspicious','dangerous','blacklist') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'safe' COMMENT '风险等级',
  `account_count` int NOT NULL DEFAULT 1 COMMENT '关联账户数',
  `account_ids` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '关联账户ID列表JSON',
  `login_count` int NOT NULL DEFAULT 0 COMMENT '登录次数',
  `last_login_time` int UNSIGNED NULL DEFAULT NULL COMMENT '最后登录时间',
  `last_login_ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '最后登录IP',
  `ban_expire_time` int UNSIGNED NULL DEFAULT NULL COMMENT '封禁到期时间',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_device_id`(`device_id` ASC) USING BTREE,
  INDEX `idx_device_hash`(`device_hash` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_risk_level`(`risk_level` ASC) USING BTREE,
  INDEX `idx_root_detected`(`root_detected` ASC) USING BTREE,
  INDEX `idx_emulator_detected`(`emulator_detected` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '设备指纹表' ROW_FORMAT = Dynamic;

