-- ----------------------------
-- Table structure for advn_ems
-- ----------------------------
DROP TABLE IF EXISTS `advn_ems`;
CREATE TABLE `advn_ems`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `event` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '事件',
  `email` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '邮箱',
  `code` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '验证码',
  `times` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '验证次数',
  `ip` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'IP',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邮箱验证码表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_ems
-- ----------------------------

-- ----------------------------
-- Table structure for advn_game_task_record
-- ----------------------------
DROP TABLE IF EXISTS `advn_game_task_record`;
CREATE TABLE `advn_game_task_record`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `game_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '游戏类型: spin/scratch/quiz/lucky_wheel/turntable',
  `game_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '游戏名称',
  `task_id` int UNSIGNED NULL DEFAULT NULL COMMENT '关联任务ID',
  `is_win` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否中奖: 0=未中奖, 1=中奖',
  `reward_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '奖励类型: coin/redpacket/item',
  `reward_amount` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '奖励金额(金币)',
  `reward_detail` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '奖励详情(JSON)',
  `receive_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '领取状态: 0=未领取, 1=已领取',
  `receive_time` int UNSIGNED NULL DEFAULT NULL COMMENT '领取时间',
  `game_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '游戏数据(JSON)',
  `score` int UNSIGNED NULL DEFAULT 0 COMMENT '游戏得分',
  `duration` int UNSIGNED NULL DEFAULT 0 COMMENT '游戏时长(秒)',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'IP',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备ID',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间戳',
  `create_date` date NULL DEFAULT NULL COMMENT '创建日期',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_game_type`(`game_type` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '游戏任务记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_game_task_record
-- ----------------------------

-- ----------------------------
-- Table structure for advn_invite_commission_config
-- ----------------------------
DROP TABLE IF EXISTS `advn_invite_commission_config`;
CREATE TABLE `advn_invite_commission_config`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '配置名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '配置代码: withdraw/video/red_packet',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '配置描述',
  `level1_rate` decimal(10, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '一级分佣比例(0.2表示20%)',
  `level2_rate` decimal(10, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '二级分佣比例',
  `level1_fixed` decimal(10, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '一级固定金额(元)',
  `level2_fixed` decimal(10, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '二级固定金额(元)',
  `calc_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'rate' COMMENT '计算方式: rate=比例, fixed=固定, rate_and_fixed=比例+固定',
  `min_amount` decimal(10, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '最低触发金额(元)',
  `max_commission` decimal(10, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '单笔最大佣金(元, 0=不限)',
  `daily_limit` int UNSIGNED NULL DEFAULT 0 COMMENT '每日最大佣金次数(0=不限)',
  `user_level_min` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '最低用户等级要求',
  `need_realname` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否需要实名: 0=否, 1=是',
  `status` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '状态: 0=禁用, 1=启用',
  `sort` int UNSIGNED NULL DEFAULT 0 COMMENT '排序',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_code`(`code` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '分佣配置表' ROW_FORMAT = Dynamic;

