-- ----------------------------
-- Table structure for advn_invite_commission_log
-- ----------------------------
DROP TABLE IF EXISTS `advn_invite_commission_log`;
CREATE TABLE `advn_invite_commission_log`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `order_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '分佣订单号',
  `source_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '来源类型: withdraw/video/red_packet/game',
  `source_id` int UNSIGNED NULL DEFAULT NULL COMMENT '来源记录ID',
  `source_order_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '来源订单号',
  `user_id` int UNSIGNED NOT NULL COMMENT '产生收益的用户ID(下级)',
  `parent_id` int UNSIGNED NOT NULL COMMENT '获得佣金的用户ID(上级)',
  `level` tinyint UNSIGNED NOT NULL COMMENT '层级: 1=一级, 2=二级',
  `source_amount` decimal(10, 4) UNSIGNED NOT NULL COMMENT '来源金额(元)',
  `commission_rate` decimal(10, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '分佣比例',
  `commission_fixed` decimal(10, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '固定佣金',
  `commission_amount` decimal(10, 4) UNSIGNED NOT NULL COMMENT '佣金金额(元)',
  `coin_amount` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '佣金金币',
  `status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '状态: 0=待结算, 1=已结算, 2=已取消, 3=已冻结',
  `settle_time` int UNSIGNED NULL DEFAULT NULL COMMENT '结算时间',
  `cancel_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '取消原因',
  `config_id` int UNSIGNED NULL DEFAULT NULL COMMENT '使用的配置ID',
  `remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_no`(`order_no` ASC) USING BTREE,
  INDEX `idx_source`(`source_type` ASC, `source_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_parent_id`(`parent_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 26 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '分佣记录表' ROW_FORMAT = Dynamic;

