-- ----------------------------
-- Table structure for advn_invite_commission_log_archive
-- ----------------------------
DROP TABLE IF EXISTS `advn_invite_commission_log_archive`;
CREATE TABLE `advn_invite_commission_log_archive`  (
  `id` int UNSIGNED NOT NULL COMMENT '日志ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '获得佣金的用户ID',
  `from_user_id` int UNSIGNED NOT NULL COMMENT '贡献佣金的用户ID',
  `order_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单类型: video/task/withdraw',
  `order_id` int UNSIGNED NULL DEFAULT NULL COMMENT '关联订单ID',
  `order_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '关联订单号',
  `order_amount` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '订单金额(金币)',
  `commission_rate` decimal(10, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '佣金比例',
  `commission_amount` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '佣金金额(金币)',
  `commission_level` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '佣金等级: 1=一级, 2=二级',
  `status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '状态: 0=待结算, 1=已结算, 2=已取消, 3=已冻结',
  `settle_time` int UNSIGNED NULL DEFAULT NULL COMMENT '结算时间',
  `cancel_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '取消原因',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_from_user_id`(`from_user_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邀请分佣日志归档表' ROW_FORMAT = Dynamic;

