-- Records of advn_invite_commission_log_archive
-- ----------------------------

-- ----------------------------
-- Table structure for advn_invite_relation
-- ----------------------------
DROP TABLE IF EXISTS `advn_invite_relation`;
CREATE TABLE `advn_invite_relation`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '被邀请人ID(当前用户)',
  `parent_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '一级邀请人ID(直接上级)',
  `grandparent_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '二级邀请人ID(间接上级)',
  `invite_code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '使用的邀请码',
  `invite_channel` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邀请渠道: link/qrcode/share',
  `invite_scene` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邀请场景',
  `register_reward_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '注册奖励状态: 0=未发放, 1=已发放',
  `register_reward_time` int UNSIGNED NULL DEFAULT NULL COMMENT '注册奖励发放时间',
  `invite_ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邀请行为IP',
  `invite_device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邀请设备ID',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间戳',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间戳',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_parent_id`(`parent_id` ASC) USING BTREE,
  INDEX `idx_grandparent_id`(`grandparent_id` ASC) USING BTREE,
  INDEX `idx_invite_code`(`invite_code` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 28 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邀请关系表' ROW_FORMAT = Dynamic;

