-- ----------------------------
-- Table structure for advn_invite_relation_migration_log
-- ----------------------------
DROP TABLE IF EXISTS `advn_invite_relation_migration_log`;
CREATE TABLE `advn_invite_relation_migration_log`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `user_id` int NOT NULL DEFAULT 0 COMMENT '用户ID',
  `old_parent_id` int NOT NULL DEFAULT 0 COMMENT '原上级ID',
  `old_grandparent_id` int NOT NULL DEFAULT 0 COMMENT '原二级上级ID',
  `new_parent_id` int NOT NULL DEFAULT 0 COMMENT '新上级ID',
  `new_grandparent_id` int NOT NULL DEFAULT 0 COMMENT '新二级上级ID',
  `admin_id` int NOT NULL DEFAULT 0 COMMENT '操作管理员ID',
  `reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '迁移原因',
  `createtime` int NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_old_parent_id`(`old_parent_id` ASC) USING BTREE,
  INDEX `idx_new_parent_id`(`new_parent_id` ASC) USING BTREE,
  INDEX `idx_admin_id`(`admin_id` ASC) USING BTREE,
  INDEX `idx_createtime`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '邀请关系迁移记录表' ROW_FORMAT = Dynamic;

