-- ----------------------------
-- Table structure for advn_ip_risk
-- ----------------------------
DROP TABLE IF EXISTS `advn_ip_risk`;
CREATE TABLE `advn_ip_risk`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'IP地址',
  `ip_type` enum('ipv4','ipv6') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ipv4' COMMENT 'IP类型',
  `risk_score` int NOT NULL DEFAULT 0 COMMENT '风险分值',
  `risk_level` enum('safe','suspicious','dangerous','blacklist') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'safe' COMMENT '风险等级',
  `account_count` int NOT NULL DEFAULT 0 COMMENT '关联账户数',
  `account_ids` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '关联账户ID列表JSON',
  `proxy_detected` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否检测到代理',
  `proxy_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '代理类型',
  `country` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '国家',
  `province` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '省份',
  `city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '城市',
  `isp` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '运营商',
  `request_count` int NOT NULL DEFAULT 0 COMMENT '请求次数',
  `violation_count` int NOT NULL DEFAULT 0 COMMENT '违规次数',
  `last_request_time` int UNSIGNED NULL DEFAULT NULL COMMENT '最后请求时间',
  `ban_expire_time` int UNSIGNED NULL DEFAULT NULL COMMENT '封禁到期时间',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_ip`(`ip` ASC) USING BTREE,
  INDEX `idx_risk_level`(`risk_level` ASC) USING BTREE,
  INDEX `idx_risk_score`(`risk_score` ASC) USING BTREE,
  INDEX `idx_proxy_detected`(`proxy_detected` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'IP风控表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_ip_risk
-- ----------------------------

