-- ----------------------------
-- Table structure for advn_migration_record
-- ----------------------------
DROP TABLE IF EXISTS `advn_migration_record`;
CREATE TABLE `advn_migration_record`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `migration_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '迁移文件名',
  `migration_path` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '迁移文件路径',
  `batch` int UNSIGNED NULL DEFAULT 0 COMMENT '批次号',
  `status` enum('pending','running','completed','failed') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'pending' COMMENT '执行状态',
  `executed_at` int UNSIGNED NULL DEFAULT NULL COMMENT '执行时间',
  `execution_time` decimal(10, 2) NULL DEFAULT NULL COMMENT '执行耗时(秒)',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '错误信息',
  `checksum` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '文件MD5校验',
  `created_at` int UNSIGNED NULL DEFAULT 0 COMMENT '创建时间',
  `updated_at` int UNSIGNED NULL DEFAULT 0 COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_migration_name`(`migration_name` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_batch`(`batch` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 70 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '数据迁移记录表' ROW_FORMAT = Dynamic;

