-- ----------------------------
-- Table structure for advn_red_packet_record
-- ----------------------------
DROP TABLE IF EXISTS `advn_red_packet_record`;
CREATE TABLE `advn_red_packet_record`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `task_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '任务ID',
  `user_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `amount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '领取金额',
  `status` tinyint(1) NULL DEFAULT 1 COMMENT '状态:1=已领取,2=已提现',
  `createtime` bigint NULL DEFAULT NULL COMMENT '领取时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `task_user`(`task_id` ASC, `user_id` ASC) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '红包领取记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_red_packet_record
-- ----------------------------
INSERT INTO `advn_red_packet_record` VALUES (1, 1, 1, 1000.00, 1, NULL);

-- ----------------------------
-- Table structure for advn_red_packet_record_archive
-- ----------------------------
DROP TABLE IF EXISTS `advn_red_packet_record_archive`;
CREATE TABLE `advn_red_packet_record_archive`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `packet_id` int UNSIGNED NOT NULL COMMENT '红包ID',
  `packet_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '红包类型',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `amount` decimal(18, 2) UNSIGNED NOT NULL COMMENT '获得金币数量',
  `status` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '状态: 0=已退回, 1=正常',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '领取IP',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备ID',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间戳',
  `create_date` date NULL DEFAULT NULL COMMENT '创建日期',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '红包领取记录归档表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_red_packet_record_archive
-- ----------------------------
INSERT INTO `advn_red_packet_record_archive` VALUES (1, 1, 'download', 1, 1000.00, 1, '127.0.0.1', '1', NULL, NULL);

-- ----------------------------
-- Table structure for advn_red_packet_resource
-- ----------------------------
DROP TABLE IF EXISTS `advn_red_packet_resource`;
CREATE TABLE `advn_red_packet_resource`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '资源名称',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '资源描述',
  `logo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '资源图标',
  `url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '跳转链接',
  `type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'miniapp' COMMENT '类型:miniapp=小程序,download=下载App,game=游戏,video=视频',
  `miniapp_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '小程序AppID',
  `miniapp_path` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '小程序页面路径',
  `miniapp_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'release' COMMENT '小程序类型:release=正式版,trial=体验版,develop=开发版',
  `download_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'App下载链接',
  `download_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '下载类型:android,ios',
  `package_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '包名',
  `app_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '小程序AppID/游戏ID',
  `video_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '视频链接',
  `video_duration` int UNSIGNED NULL DEFAULT 0 COMMENT '视频时长(秒)',
  `chat_duration` int UNSIGNED NOT NULL DEFAULT 30 COMMENT '聊天时长(秒)',
  `chat_requirement` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '聊天要求内容',
  `miniapp_duration` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '小程序游戏时长(秒)',
  `adv_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '广告位ID',
  `adv_platform` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '广告平台(gromore/gdt等)',
  `adv_duration` int UNSIGNED NOT NULL DEFAULT 30 COMMENT '广告时长(秒)',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '图片JSON数组',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '权重',
  `sort` int UNSIGNED NULL DEFAULT 0 COMMENT '排序',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `type`(`type` ASC) USING BTREE,
  INDEX `status`(`status` ASC) USING BTREE,
  INDEX `idx_sort`(`sort` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 48 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '红包资源表' ROW_FORMAT = Dynamic;

