-- ----------------------------
-- Table structure for advn_red_packet_reward_config
-- ----------------------------
DROP TABLE IF EXISTS `advn_red_packet_reward_config`;
CREATE TABLE `advn_red_packet_reward_config`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '配置名称',
  `start_hour` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '开始小时(0-23)，0表示不限制',
  `end_hour` tinyint UNSIGNED NOT NULL DEFAULT 24 COMMENT '结束小时(0-24)，24表示不限制',
  `min_today_amount` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '今日领取金额下限(金币)，0表示不限制',
  `max_today_amount` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '今日领取金额上限(金币)，0表示无上限',
  `base_min_reward` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '老用户基础奖励下限(金币)',
  `base_max_reward` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '老用户基础奖励上限(金币)',
  `accumulate_min_reward` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '老用户累加奖励下限(金币)',
  `accumulate_max_reward` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '老用户累加奖励上限(金币)',
  `new_user_base_min` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '新用户基础奖励下限(金币)',
  `new_user_base_max` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '新用户基础奖励上限(金币)',
  `new_user_accumulate_min` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '新用户累加奖励下限(金币)',
  `new_user_accumulate_max` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '新用户累加奖励上限(金币)',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '排序权重(数值越大优先级越高)',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '备注说明',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `time_range`(`start_hour` ASC, `end_hour` ASC) USING BTREE,
  INDEX `today_amount`(`min_today_amount` ASC, `max_today_amount` ASC) USING BTREE,
  INDEX `status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '红包奖励配置表' ROW_FORMAT = Dynamic;

