-- ----------------------------
-- Table structure for advn_red_packet_task
-- ----------------------------
DROP TABLE IF EXISTS `advn_red_packet_task`;
CREATE TABLE `advn_red_packet_task`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '红包名称/祝福语',
  `display_title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '展示标题(可选，不填则使用资源名称)',
  `display_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '展示描述(可选，不填则使用资源描述)',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '红包描述',
  `type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '类型:normal=普通红包,lucky=拼手气红包,video=视频红包,miniapp=小程序红包,download=下载红包,game=游戏红包',
  `show_red_packet` tinyint(1) NULL DEFAULT 1 COMMENT '是否显示红包: 0=否, 1=是',
  `max_click_per_day` int UNSIGNED NULL DEFAULT 10 COMMENT '每日最大点击次数',
  `total_amount` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '总金额',
  `total_count` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '红包总数',
  `reward` decimal(10, 2) NOT NULL DEFAULT 0.00 COMMENT '单个红包金额',
  `resource_id` int UNSIGNED NULL DEFAULT 0 COMMENT '关联资源ID',
  `status` enum('pending','normal','finished','expired') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态:pending=待发送,normal=进行中,finished=已抢完,expired=已过期',
  `start_time` bigint NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` bigint NULL DEFAULT NULL COMMENT '结束时间',
  `expire_time` int UNSIGNED NULL DEFAULT 86400 COMMENT '过期时间(秒),默认24小时',
  `sender_id` int UNSIGNED NULL DEFAULT 0 COMMENT '发送者ID',
  `sender_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '发送者名称',
  `sender_avatar` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '发送者头像',
  `push_status` tinyint(1) NULL DEFAULT 0 COMMENT '推送状态:0=未推送,1=已推送',
  `push_time` bigint NULL DEFAULT NULL COMMENT '推送时间',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '权重',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `type`(`type` ASC) USING BTREE,
  INDEX `status`(`status` ASC) USING BTREE,
  INDEX `resource_id`(`resource_id` ASC) USING BTREE,
  INDEX `sender_id`(`sender_id` ASC) USING BTREE,
  INDEX `idx_push_status`(`push_status` ASC) USING BTREE,
  INDEX `idx_resource_id`(`resource_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '红包任务表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_red_packet_task
-- ----------------------------

