-- ----------------------------
-- Table structure for advn_redpacket_daily_stat
-- ----------------------------
DROP TABLE IF EXISTS `advn_redpacket_daily_stat`;
CREATE TABLE `advn_redpacket_daily_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `stat_date` date NOT NULL COMMENT '统计日期',
  `task_count` int UNSIGNED NULL DEFAULT 0 COMMENT '任务创建数',
  `task_pushed_count` int UNSIGNED NULL DEFAULT 0 COMMENT '任务推送数',
  `task_finished_count` int UNSIGNED NULL DEFAULT 0 COMMENT '任务完成数',
  `participation_count` int UNSIGNED NULL DEFAULT 0 COMMENT '参与人数',
  `participation_amount` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '参与金额',
  `collected_count` int UNSIGNED NULL DEFAULT 0 COMMENT '领取人数',
  `collected_amount` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '领取金额',
  `new_user_count` int UNSIGNED NULL DEFAULT 0 COMMENT '新用户数',
  `new_user_amount` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '新用户金额',
  `old_user_count` int UNSIGNED NULL DEFAULT 0 COMMENT '老用户数',
  `old_user_amount` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '老用户金额',
  `createtime` int UNSIGNED NULL DEFAULT NULL,
  `updatetime` int UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_stat_date`(`stat_date` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '每日红包统计表' ROW_FORMAT = Dynamic;

