-- ----------------------------
-- Table structure for advn_risk_rule
-- ----------------------------
DROP TABLE IF EXISTS `advn_risk_rule`;
CREATE TABLE `advn_risk_rule`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `rule_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则编码',
  `rule_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则名称',
  `rule_type` enum('video','task','withdraw','redpacket','invite','global') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'global' COMMENT '规则类型',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '规则描述',
  `threshold` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT '阈值',
  `score_weight` int NOT NULL DEFAULT 10 COMMENT '违规分值权重(1-100)',
  `action` enum('warn','block','freeze','ban') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'warn' COMMENT '触发动作',
  `action_duration` int NOT NULL DEFAULT 0 COMMENT '动作持续时间(秒,0永久)',
  `enabled` tinyint(1) NOT NULL DEFAULT 1 COMMENT '是否启用',
  `level` tinyint(1) NOT NULL DEFAULT 1 COMMENT '风险等级(1低2中3高)',
  `extra_config` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '额外配置JSON',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_rule_code`(`rule_code` ASC) USING BTREE,
  INDEX `idx_rule_type`(`rule_type` ASC) USING BTREE,
  INDEX `idx_enabled`(`enabled` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 36 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '风控规则配置表' ROW_FORMAT = Dynamic;

