-- ----------------------------
-- Table structure for advn_risk_stat
-- ----------------------------
DROP TABLE IF EXISTS `advn_risk_stat`;
CREATE TABLE `advn_risk_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `stat_date` date NOT NULL COMMENT '统计日期',
  `total_requests` bigint NOT NULL DEFAULT 0 COMMENT '总请求数',
  `blocked_requests` bigint NOT NULL DEFAULT 0 COMMENT '拦截请求数',
  `warn_count` int NOT NULL DEFAULT 0 COMMENT '警告次数',
  `block_count` int NOT NULL DEFAULT 0 COMMENT '拦截次数',
  `freeze_count` int NOT NULL DEFAULT 0 COMMENT '冻结次数',
  `ban_count` int NOT NULL DEFAULT 0 COMMENT '封禁次数',
  `unique_ip_count` int NOT NULL DEFAULT 0 COMMENT '独立IP数',
  `unique_device_count` int NOT NULL DEFAULT 0 COMMENT '独立设备数',
  `proxy_detected_count` int NOT NULL DEFAULT 0 COMMENT '检测到代理数',
  `emulator_detected_count` int NOT NULL DEFAULT 0 COMMENT '检测到模拟器数',
  `rule_trigger_stats` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '规则触发统计JSON',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_stat_date`(`stat_date` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 31 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '风控统计表' ROW_FORMAT = Dynamic;

