-- ----------------------------
-- Table structure for advn_shop_address
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_address`;
CREATE TABLE `advn_shop_address`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '编号',
  `user_id` int NULL DEFAULT NULL COMMENT '用户ID',
  `province_id` int NULL DEFAULT NULL COMMENT '省id',
  `city_id` int NULL DEFAULT NULL COMMENT '市id',
  `area_id` int NULL DEFAULT NULL COMMENT '区域ID',
  `receiver` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '收货人',
  `mobile` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '地址详情',
  `zipcode` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '邮编',
  `usednums` int UNSIGNED NULL DEFAULT 0 COMMENT '使用次数',
  `createtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  `isdefault` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否默认',
  `status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '收货地址' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_address
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_area
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_area`;
CREATE TABLE `advn_shop_area`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `pid` int NULL DEFAULT NULL COMMENT '父ID',
  `level` tinyint(1) NULL DEFAULT 0 COMMENT '等级',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '名称',
  `pinyin` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '拼音',
  `py` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '拼音前缀',
  `adcode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '唯一ID',
  `zipcode` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '邮编',
  `lng` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '经度',
  `lat` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '纬度',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'normal' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `pid`(`pid` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '地区表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_area
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_attribute
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_attribute`;
CREATE TABLE `advn_shop_attribute`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `category_id` int NULL DEFAULT NULL COMMENT '分类ID',
  `is_search` tinyint(1) NULL DEFAULT 0 COMMENT '是否可搜索:0=否,1=是',
  `is_must` tinyint(1) NULL DEFAULT 0 COMMENT '是否必填:0=可选,1=必选',
  `type` enum('radio','checkbox') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'radio' COMMENT '类型:radio=单选,checkbox=多选',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名称',
  `createtime` bigint NULL DEFAULT NULL COMMENT '添加时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品属性' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_attribute
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_attribute_value
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_attribute_value`;
CREATE TABLE `advn_shop_attribute_value`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `attribute_id` int NULL DEFAULT NULL COMMENT '属性ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名称',
  `createtime` bigint NULL DEFAULT NULL COMMENT '添加时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品属性值' ROW_FORMAT = Dynamic;

