-- ----------------------------
-- Table structure for advn_shop_comment
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_comment`;
CREATE TABLE `advn_shop_comment`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `pid` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '父评论ID',
  `user_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '会员ID',
  `order_id` int NULL DEFAULT NULL COMMENT '订单ID',
  `goods_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '关联ID',
  `star` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '评分',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '内容',
  `comments` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '评论数',
  `images` varchar(1500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '评论图片',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'IP',
  `useragent` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'User Agent',
  `subscribe` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '订阅',
  `createtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `post_id`(`goods_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '评论表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_comment
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_coupon
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_coupon`;
CREATE TABLE `advn_shop_coupon`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名称',
  `condition_ids` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '条件ids',
  `result` tinyint NULL DEFAULT NULL COMMENT '结果:0=订单满xx打x折,1=订单满xx减x元',
  `result_data` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '结果补充',
  `mode` enum('fixation','dates') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'dates' COMMENT '有效期模式:fixation=固定天数,dates=日期范围',
  `is_private` enum('yes','no') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'no' COMMENT '是否私有:yes=是,no=否',
  `is_open` tinyint(1) NULL DEFAULT 1 COMMENT '是否开启:0=关闭,1=开启',
  `allow_num` int NULL DEFAULT 1 COMMENT '一人可领取数量',
  `give_num` int NULL DEFAULT 1 COMMENT '发放总量',
  `received_num` int NULL DEFAULT 0 COMMENT '已经领取数量',
  `receive_times` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '领取时间段',
  `begintime` bigint NULL DEFAULT NULL COMMENT '领取开始时间',
  `endtime` bigint NULL DEFAULT NULL COMMENT '领取结束时间',
  `use_times` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '使用时间段',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '优惠券表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_coupon
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_coupon_condition
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_coupon_condition`;
CREATE TABLE `advn_shop_coupon_condition`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '条件名称',
  `type` tinyint NULL DEFAULT NULL COMMENT '类型:1=指定商品,2=新用户专享,3=老用户专享',
  `content` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '条件补充内容',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '优惠券条件' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_coupon_condition
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_electronics_order
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_electronics_order`;
CREATE TABLE `advn_shop_electronics_order`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `shipper_id` int NULL DEFAULT NULL COMMENT '快递公司id',
  `paytype` tinyint(1) NULL DEFAULT 1 COMMENT '运费支付方式:1=现付,2=到付,3=月结,4=第三方付(仅SF支持)',
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '线下网点客户号',
  `customer_pwd` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '线下网点密码',
  `send_site` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '网点名称',
  `send_staff` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '网点快递员',
  `month_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '月结编号',
  `is_notice` tinyint(1) NULL DEFAULT 0 COMMENT '是否通知揽件:0=通知揽件,1=不通知揽件',
  `is_return_temp` tinyint(1) NULL DEFAULT NULL COMMENT '是否返回电子面单模板:0=不返回,1=返回',
  `is_send_message` tinyint(1) NULL DEFAULT NULL COMMENT '是否需要短信提醒:0=否,1=是',
  `template_size` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '模板尺寸',
  `operate_require` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '签回单操作要求(如：签名、盖章、身份证复印件等)',
  `logistic_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '快递单号(仅宅急送可用)',
  `start_date` int NULL DEFAULT NULL COMMENT '上门揽件开始时间',
  `end_date` int NULL DEFAULT NULL COMMENT '上门揽件结束时间',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `exp_type` tinyint(1) NULL DEFAULT NULL COMMENT '快递类型:1=标准快件',
  `is_return_sign_bill` tinyint(1) NULL DEFAULT NULL COMMENT '是否要签回单:0=否,1=是',
  `company` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人公司',
  `province_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人省',
  `city_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人市',
  `exp_area_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人区',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人详细地址',
  `name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人姓名',
  `tel` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人电话',
  `mobile` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件人手机号码',
  `post_code` varchar(15) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '发件地邮编',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '自定义名称',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '电子面单' ROW_FORMAT = Dynamic;

