DROP TABLE IF EXISTS `advn_shop_freight`;
CREATE TABLE `advn_shop_freight`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '名称',
  `type` tinyint(1) NULL DEFAULT NULL COMMENT '是否包邮:1=按件计,2=按重计',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '权重',
  `switch` tinyint(1) NOT NULL DEFAULT 0 COMMENT '开关',
  `num` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '默认件/重',
  `price` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '默认价格',
  `continue_num` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '续件/续重',
  `continue_price` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '续费',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '运费模板' ROW_FORMAT = Dynamic;

