-- ----------------------------
-- Table structure for advn_shop_goods
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_goods`;
CREATE TABLE `advn_shop_goods`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '商品id',
  `category_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '类别ID',
  `subtitle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '子标题',
  `attribute_ids` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '属性值ids',
  `brand_id` int NULL DEFAULT NULL COMMENT '品牌ID',
  `goods_sn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '货号',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '商品标题',
  `keywords` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '关键字',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '描述',
  `marketprice` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '市场售价',
  `price` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '商城售价',
  `stocks` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '库存',
  `sales` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '销量',
  `guarantee_ids` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '服务保障',
  `star` int NULL DEFAULT 0 COMMENT '星级',
  `views` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '浏览次数',
  `comments` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '评论数',
  `shares` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '分享次数',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '缩略图',
  `images` varchar(1500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '预览图',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '商品内容详情',
  `corner` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '角标文字',
  `flag` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '标志',
  `spectype` tinyint(1) NULL DEFAULT 0 COMMENT '规格类型:0=单规格,1=多规格',
  `weight` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '重量(kg)',
  `isvirtual` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '虚拟物品',
  `freight_id` int NULL DEFAULT NULL COMMENT '运费模板ID',
  `weigh` int NOT NULL DEFAULT 1 COMMENT '排序',
  `createtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` bigint NULL DEFAULT NULL COMMENT '删除时间',
  `status` enum('normal','hidden','soldout') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `category_id`(`category_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 25 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_goods
-- ----------------------------
