-- ----------------------------
-- Table structure for advn_shop_goods_sku
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_goods_sku`;
CREATE TABLE `advn_shop_goods_sku`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `goods_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '商品ID',
  `goods_sn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '货号',
  `sku_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT 'SKU',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '规格封面',
  `price` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '价格',
  `marketprice` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '市场价',
  `stocks` int NOT NULL DEFAULT 0 COMMENT '库存数量',
  `sales` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '销量',
  `weigh` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '权重',
  `createtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '添加时间',
  `updatetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 51 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '商品SKU表' ROW_FORMAT = Dynamic;

