-- ----------------------------
-- Table structure for advn_shop_order
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_order`;
CREATE TABLE `advn_shop_order`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '自增ID',
  `order_sn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT ' 订单号,唯一',
  `user_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户id,',
  `address_id` int UNSIGNED NULL DEFAULT NULL COMMENT '收款地址ID',
  `province_id` int NULL DEFAULT NULL COMMENT '省id',
  `city_id` int NULL DEFAULT NULL COMMENT '市id',
  `area_id` int NULL DEFAULT NULL COMMENT '区域ID',
  `user_coupon_id` int NULL DEFAULT NULL COMMENT '优惠券记录ID',
  `openid` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'Openid',
  `receiver` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '收货人的姓名',
  `address` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '收货人的地址',
  `zipcode` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '收货人的邮编',
  `mobile` varchar(60) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '收货人的手机',
  `amount` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '订单总金额',
  `discount` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '优惠金额',
  `shippingfee` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '配送费用',
  `goodsprice` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '商品总费用',
  `saleamount` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '应付款金额',
  `payamount` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '实际付款金额',
  `paytype` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '用户选择的支付方式名称',
  `method` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '支付方法',
  `transactionid` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '交易流水号',
  `expressname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '快递名称',
  `expressno` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '快递单号',
  `createtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `expiretime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '过期时间',
  `paytime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '支付时间',
  `refundtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '退货时间',
  `shippingtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '配送时间',
  `receivetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '收货时间',
  `canceltime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '取消时间',
  `deletetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  `orderstate` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '订单状态:0=正常,1=已取消,2=已失效,3=已完成,4=退货退款中',
  `shippingstate` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '配送状态:0=未发货,1=已发货,2=已收货',
  `paystate` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '支付状态:0=未付款,1=已付款',
  `memo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` enum('normal','hidden') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态:normal=正常,hidden=隐藏',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `order_sn`(`order_sn` ASC) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  INDEX `orderstate`(`orderstate` ASC) USING BTREE,
  INDEX `paytime`(`paytime` ASC) USING BTREE,
  INDEX `createtime`(`createtime` ASC) USING BTREE,
  INDEX `province_city_area`(`province_id` ASC, `city_id` ASC, `area_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '订单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_order
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_order_action
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_order_action`;
CREATE TABLE `advn_shop_order_action`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '流水号',
  `order_sn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '订单编号',
  `operator` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '操作人',
  `memo` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '操作记录(备注)',
  `createtime` bigint NULL DEFAULT NULL COMMENT '操作时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `order_id`(`order_sn` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '订单操作记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_order_action
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_order_aftersales
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_order_aftersales`;
CREATE TABLE `advn_shop_order_aftersales`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '编号',
  `order_id` int NULL DEFAULT NULL COMMENT '订单id',
  `order_goods_id` int NULL DEFAULT NULL COMMENT '订单商品id',
  `user_id` int UNSIGNED NULL DEFAULT NULL COMMENT '用户ID',
  `type` tinyint UNSIGNED NOT NULL DEFAULT 1 COMMENT '售后类型:1=仅退款,2=退款退货',
  `nums` int UNSIGNED NULL DEFAULT 0 COMMENT '数量',
  `realprice` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '商品实付金额',
  `shippingfee` tinyint(1) NULL DEFAULT 0 COMMENT '邮费',
  `refund` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '退款金额',
  `reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '退款原因',
  `images` varchar(2500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '补充图片',
  `mark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '卖家备注',
  `status` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '状态:1=待审核,2=审核通过,3=审核拒绝',
  `expressname` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '' COMMENT '快递名称',
  `expressno` varchar(50) CHARACTER SET utf8mb3 COLLATE utf8mb3_general_ci NULL DEFAULT '' COMMENT '快递单号',
  `createtime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '退货单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_order_aftersales
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_order_electronics
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_order_electronics`;
CREATE TABLE `advn_shop_order_electronics`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `order_sn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单编号',
  `print_template` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '模板',
  `kdn_order_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'KDNOrderCode',
  `logistic_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物流单号',
  `shipper_code` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '快递编号',
  `order` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '线下网点客户号',
  `customer_pwd` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '线下网点密码',
  `status` tinyint(1) NULL DEFAULT 0 COMMENT '状态:0=正常,1=已取消',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '订单电子面单记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_order_electronics
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_order_goods
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_order_goods`;
CREATE TABLE `advn_shop_order_goods`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键id',
  `order_sn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '0' COMMENT '订单号',
  `goods_sn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '' COMMENT '货号',
  `goods_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '商品id',
  `goods_sku_id` int NULL DEFAULT NULL COMMENT 'skuid',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物品标题',
  `nums` smallint UNSIGNED NOT NULL DEFAULT 1 COMMENT '购买商品数量',
  `marketprice` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '市场价',
  `price` decimal(10, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '商城售价',
  `realprice` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '实付金额',
  `salestate` tinyint(1) NULL DEFAULT 0 COMMENT '销售状态:0=待申请,1=已申请,2=退款中,3=退货中,4=已退款,5=已退货退款,6=已拒绝',
  `commentstate` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '评论状态:0=未评论,1=已评论',
  `attrdata` varchar(1500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '属性信息',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '图片',
  `weight` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '重量(kg)',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `order_id`(`order_sn` ASC) USING BTREE,
  INDEX `goods_id`(`goods_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '订单商品表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_shop_order_goods
-- ----------------------------

-- ----------------------------
-- Table structure for advn_shop_page
-- ----------------------------
DROP TABLE IF EXISTS `advn_shop_page`;
CREATE TABLE `advn_shop_page`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `category_id` int NOT NULL DEFAULT 0 COMMENT '分类ID',
  `admin_id` int UNSIGNED NULL DEFAULT 0 COMMENT '管理员ID',
  `type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '类型',
  `title` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '标题',
  `seotitle` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'SEO标题',
  `keywords` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '关键字',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '描述',
  `flag` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '标志',
  `image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '头像',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '内容',
  `icon` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '图标',
  `views` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '点击',
  `likes` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '点赞',
  `dislikes` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '点踩',
  `diyname` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '自定义',
  `showtpl` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '视图模板',
  `parsetpl` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '解析模板标签',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` bigint NULL DEFAULT NULL COMMENT '删除时间',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '权重',
  `status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '状态',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `diyname`(`diyname` ASC) USING BTREE,
  INDEX `type`(`type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '单页表' ROW_FORMAT = Dynamic;

