-- ----------------------------
-- Table structure for advn_signin_record
-- ----------------------------
DROP TABLE IF EXISTS `advn_signin_record`;
CREATE TABLE `advn_signin_record`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `signin_date` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '签到日期 YYYY-MM-DD',
  `coins` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '获得金币数量',
  `type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'daily' COMMENT '签到类型: daily=日常签到, fillup=补签',
  `successions` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '连续签到天数',
  `createtime` int UNSIGNED NULL DEFAULT 0 COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id` ASC, `signin_date` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_signin_date`(`signin_date` ASC) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '签到记录表' ROW_FORMAT = Dynamic;

