-- Table structure for advn_signin_rule
-- ----------------------------
DROP TABLE IF EXISTS `advn_signin_rule`;
CREATE TABLE `advn_signin_rule`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `day` int UNSIGNED NOT NULL COMMENT '周期第几天(7天一循环)',
  `coins` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '奖励金币数量',
  `description` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '规则描述',
  `createtime` int UNSIGNED NULL DEFAULT 0 COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT 0 COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_day`(`day` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '签到奖励规则表' ROW_FORMAT = Dynamic;

