-- ----------------------------
-- Table structure for advn_singlepage
-- ----------------------------
DROP TABLE IF EXISTS `advn_singlepage`;
CREATE TABLE `advn_singlepage`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `category_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '分类ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '页面标题',
  `keywords` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT 'SEO关键词',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT 'SEO描述',
  `image` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '封面图片',
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '页面内容(富文本)',
  `tpl` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '自定义模板',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '权重(排序)',
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '状态: 1=启用, 0=禁用',
  `createtime` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '创建时间',
  `updatetime` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '更新时间',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_category_id`(`category_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_weigh`(`weigh` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '单页管理表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_singlepage
-- ----------------------------
INSERT INTO `advn_singlepage` VALUES (1, 5, '欢迎使用', '公告,弹窗,通知', '首页弹窗公告示例', '', '<p style=\"text-align:center;\"></p><h2 style=\"text-align:center;color:#333;\">欢迎使用本平台</h2><p style=\"text-align:center;color:#666;font-size:14px;\">感谢您的支持与信任！</p><p><br/></p><p>1、本平台提供丰富多样的短剧内容，观看视频即可获得金币奖励；</p><p>2、金币可在钱包中申请提现，支持微信自动打款；</p><p>3、邀请好友加入还可获得额外奖励，多邀多得。</p><p><br/></p><p style=\"color:#999;font-size:12px;text-align:right;\">—— 系统公告</p>', '', 100, 1, 1775034069, 1775034534, NULL);
INSERT INTO `advn_singlepage` VALUES (2, 6, '分销规则', '分销规则,分销说明,佣金规则', '平台分销佣金的规则和说明', '', '<h2 style=\"text-align:center;color:#E62129;\">平台分销规则</h2><p><br/></p><h3 style=\"color:#333;\">一、分销等级</h3><p>平台分销共设有以下等级，根据累计佣金金额自动升级：</p><table style=\"width:100%;border-collapse:collapse;margin:10px 0;\"><thead><tr style=\"background:#E62129;color:#fff;\"><th style=\"padding:8px 12px;border:1px solid #ddd;\">等级</th><th style=\"padding:8px 12px;border:1px solid #ddd;\">名称</th><th style=\"padding:8px 12px;border:1px solid #ddd;\">累计佣金要求</th></tr></thead><tbody><tr><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv1</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">普通会员</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">0元</td></tr><tr style=\"background:#f9f9f9;\"><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv2</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">青铜代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">100元</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv3</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">白银代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">500元</td></tr><tr style=\"background:#f9f9f9;\"><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv4</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">黄金代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">2,000元</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv5</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">铂金代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">5,000元</td></tr><tr style=\"background:#f9f9f9;\"><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv6</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">钻石代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">10,000元</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv7</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">星耀代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">50,000元</td></tr><tr style=\"background:#f9f9f9;\"><td style=\"padding:8px 12px;border:1px solid #ddd;text-align:center;\">Lv8</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">王者代理</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">100,000元</td></tr></tbody></table><p><br/></p><h3 style=\"color:#333;\">二、佣金规则</h3><p>通过邀请好友注册成为您的下级，当下级在平台产生消费行为时，您可获得相应的佣金奖励：</p><p><strong>1. 一级佣金（直接邀请）</strong></p><ul class=\" list-paddingleft-2\"><li><p>您直接邀请的好友在平台消费（提现、观看视频、领取红包、游戏等），您可获得一定比例的一级佣金奖励。</p></li><li><p>一级佣金比例根据消费类型不同而有所差异，具体以平台公布为准。</p></li></ul><p><strong>2. 二级佣金（间接邀请）</strong></p><ul class=\" list-paddingleft-2\"><li><p>您直接邀请的好友再邀请其他好友，这些好友产生消费时，您也可获得一定比例的二级佣金奖励。</p></li><li><p>二级佣金比例通常低于一级佣金。</p></li></ul><p><br/></p><h3 style=\"color:#333;\">三、佣金来源</h3><table style=\"width:100%;border-collapse:collapse;margin:10px 0;\"><thead><tr style=\"background:#E62129;color:#fff;\"><th style=\"padding:8px 12px;border:1px solid #ddd;\">来源类型</th><th style=\"padding:8px 12px;border:1px solid #ddd;\">说明</th></tr></thead><tbody><tr><td style=\"padding:8px 12px;border:1px solid #ddd;\">提现分佣</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">下级用户成功提现时，上级获得佣金</td></tr><tr style=\"background:#f9f9f9;\"><td style=\"padding:8px 12px;border:1px solid #ddd;\">视频分佣</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">下级用户观看视频产生收益时，上级获得佣金</td></tr><tr><td style=\"padding:8px 12px;border:1px solid #ddd;\">红包分佣</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">下级用户领取红包时，上级获得佣金</td></tr><tr style=\"background:#f9f9f9;\"><td style=\"padding:8px 12px;border:1px solid #ddd;\">游戏分佣</td><td style=\"padding:8px 12px;border:1px solid #ddd;\">下级用户参与游戏消费时，上级获得佣金</td></tr></tbody></table><p><br/></p><h3 style=\"color:#333;\">四、佣金结算</h3><p>1. 佣金产生后进入<strong>待结算</strong>状态，系统将在一定时间后自动结算为可用余额。</p><p>2. 已结算的佣金将以金币形式发放至您的金币账户，可在钱包中申请提现。</p><p>3. 提现金额 = 金币余额 ÷ 汇率，具体汇率以平台实时公示为准。</p><p><br/></p><h3 style=\"color:#333;\">五、邀请方式</h3><p>您可以通过以下方式邀请好友：</p><ul class=\" list-paddingleft-2\"><li><p><strong>邀请链接</strong>：将您的专属邀请链接发送给好友，好友点击链接注册即成为您的下级。</p></li><li><p><strong>邀请码</strong>：将您的邀请码告知好友，好友在注册时输入邀请码即可绑定关系。</p></li><li><p><strong>二维码海报</strong>：生成专属邀请海报，好友扫码即可注册。</p></li></ul><p><br/></p><h3 style=\"color:#333;\">六、注意事项</h3><ol class=\" list-paddingleft-2\"><li><p>每位用户只能绑定一位邀请人（一级），绑定后不可更改。</p></li><li><p>禁止通过虚假交易、刷单等违规方式获取佣金，一经发现将取消佣金并封禁账号。</p></li><li><p>平台有权根据运营情况调整佣金比例和规则，调整前会提前公告。</p></li><li><p>如有疑问请联系客服咨询。</p></li></ol><p><br/></p><p style=\"color:#999;font-size:12px;text-align:right;\">—— 平台运营团队</p>', 'distribution-rules', 100, 1, 1775102444, 1775102548, NULL);
INSERT INTO `advn_singlepage` VALUES (11, 2, '新手入门指南', '新手,入门,教程,指南', '新用户快速了解平台功能与基本操作', '', '<h3>欢迎加入平台！</h3><p>本平台提供丰富的赚钱方式，以下是你需要了解的基本功能：</p><p><br/></p><h4>一、每日签到</h4><p>每天打开App点击签到即可获得金币奖励，连续签到天数越多奖励越丰厚。漏签还可以使用补签功能。</p><p><br/></p><h4>二、观看视频赚金币</h4><p>在视频页面观看完整视频即可获得金币奖励，每观看一个完整视频可获得 <b>{{video_coin_reward}}</b> 金币，每日最多可观看 <b>{{daily_video_limit}}</b> 个视频，达到上限后次日重置。</p><p><br/></p><h4>三、抢红包任务</h4><p>系统不定期发放红包任务，完成指定条件即可领取随机金额的金币红包，单个红包最高可获 <b>{{red_packet_max_reward}}</b> 金币。</p><p><br/></p><h4>四、邀请好友</h4><p>分享你的邀请码给好友，好友注册后你和好友都能获得金币奖励。每成功邀请一位好友注册可获得 <b>{{invite_register_reward}}</b> 金币，好友后续的消费还能给你带来佣金收入。</p><p><br/></p><h4>五、金币提现</h4><p>积累一定数量的金币后，可以在「我的 → 钱包 → 去提现」中申请提现到微信零钱。当前兑换比例为 <b>{{coin_rate}}</b> 金币 = 1元，最低提现 <b>{{min_withdraw}}</b> 元。</p><p><br/></p><h4>六、新人奖励</h4><p>新用户注册成功后，系统会自动发放 <b>{{new_user_coin}}</b> 金币的新人注册奖励。</p><p><br/></p><p style=\"color:#E62129;font-weight:bold;\">小提示：坚持每天签到和观看视频，日积月累金币会很可观哦！</p>', '', 100, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (12, 2, '金币获取方式', '金币,赚取,奖励,收入', '了解平台中所有获取金币的途径和规则', '', '<h3>金币获取途径一览</h3><p>平台提供多种金币获取方式，以下是详细说明：</p><p><br/></p><h4>1. 每日签到</h4><p>每日签到可获得基础金币奖励，连续签到可获得递增奖励：</p><ul><li>连续签到1天：获得基础奖励金币</li><li>连续签到3天：额外获得加签奖励</li><li>连续签到7天：获得周签额外奖励</li><li>漏签可使用金币补签（补签消耗以签到配置为准）</li></ul><p><br/></p><h4>2. 观看视频</h4><p>观看完整视频即可获得金币奖励，注意以下规则：</p><ul><li>需观看达到 <b>{{video_watch_duration}}</b> 秒以上才算有效</li><li>每观看一个完整视频可获得 <b>{{video_coin_reward}}</b> 金币</li><li>每日最多可观看 <b>{{daily_video_limit}}</b> 个视频</li><li>每小时金币获取上限 <b>{{hourly_coin_limit}}</b> 金币</li><li>每日金币获取上限 <b>{{daily_coin_limit}}</b> 金币</li><li>切勿使用模拟器或自动脚本，会被风控系统检测</li></ul><p><br/></p><h4>3. 邀请好友</h4><ul><li>每成功邀请1位好友注册：获得 <b>{{invite_register_reward}}</b> 金币奖励</li><li>好友完成首次提现：你还能额外获得 <b>{{invite_first_withdraw_reward}}</b> 金币</li></ul><p><br/></p><h4>4. 抢红包</h4><p>参与平台红包活动，有机会获得随机金币奖励，单个红包最高 <b>{{red_packet_max_reward}}</b> 金币。</p><p><br/></p><h4>5. 新人奖励</h4><p>新用户注册成功后，系统会自动发放 <b>{{new_user_coin}}</b> 金币的新人注册奖励。</p><p><br/></p><p style=\"color:#999;\">提示：每日金币获取设有上限（<b>{{daily_coin_limit}}</b> 金币/天），达到上限后请次日再来。</p>', '', 90, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (13, 2, '金币提现说明', '提现,提款,微信,到账', '了解金币提现的规则、流程和注意事项', '', '<h3>金币提现规则</h3><p><br/></p><h4>一、兑换比例</h4><p>当前金币与人民币的兑换比例为：<b style=\"color:#E62129;font-size:16px;\">{{coin_rate}} 金币 = 1.00 元</b></p><p>（例如：你有 <b>{{coin_rate}}</b> 金币即可提现 1 元）</p><p><br/></p><h4>二、提现条件</h4><ul><li>账户需完成实名认证（绑定手机号）</li><li>可提现金币余额需达到最低提现金额要求（<b>{{min_withdraw}}</b> 元）</li><li>新注册用户需满足注册天数要求（<b>{{new_user_withdraw_days}}</b> 天）后才能提现</li><li>账户状态正常，无违规记录</li></ul><p><br/></p><h4>三、提现流程</h4><ol><li>进入「我的」页面，查看钱包中的可提现金额</li><li>点击「去提现」按钮</li><li>选择提现金额（可选金额：<b>{{withdraw_amounts}}</b> 元）</li><li>确认提现信息，提交申请</li><li>等待审核：<b>{{auto_audit_amount}}</b> 元以下自动审核，<b>{{manual_audit_amount}}</b> 元以上需要人工审核</li><li>审核通过后自动打款到微信零钱</li></ol><p><br/></p><h4>四、提现限制</h4><ul><li>提现金额范围：<b>{{min_withdraw}}</b> 元 ~ <b>{{max_withdraw}}</b> 元/次</li><li>每日提现次数上限：<b>{{daily_withdraw_limit}}</b> 次</li><li>提现手续费：<b>{{fee_rate}}</b>%（手续费从提现金额中扣除）</li></ul><p><br/></p><h4>五、常见问题</h4><p><b>Q：提现多久到账？</b><br/>A：审核通过后通常即时到账，高峰期可能稍有延迟。</p><p><b>Q：提现被拒绝怎么办？</b><br/>A：请查看拒绝原因，修改后重新提交，或联系客服咨询。</p><p><b>Q：可以提现到支付宝吗？</b><br/>A：目前仅支持提现到微信零钱。</p><p><b>Q：为什么可提现金额和金币余额不一致？</b><br/>A：提现金额 = 金币余额 ÷ {{coin_rate}}，请以钱包页面显示的可提现金额为准。</p>', '', 80, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (14, 2, '邀请好友赚佣金', '邀请,推荐,分销,佣金,团队', '了解邀请好友奖励机制和佣金规则', '', '<h3>邀请好友奖励机制</h3><p>邀请好友加入平台，不仅能获得金币奖励，还能通过分销佣金持续收益！</p><p><br/></p><h4>一、如何邀请好友</h4><ol><li>进入「我的 → 邀请好友」页面</li><li>复制你的专属邀请码分享给好友</li><li>好友注册时填写你的邀请码即可绑定关系</li></ol><p><br/></p><h4>二、邀请奖励</h4><ul><li><b>一级邀请：</b>好友注册成功后，你获得 <b>{{invite_level1_reward}}</b> 金币</li><li><b>二级邀请：</b>好友的好友注册成功后，你获得 <b>{{invite_level2_reward}}</b> 金币</li><li><b>首次提现奖励：</b>你的一级好友首次成功提现后，你额外获得 <b>{{invite_first_withdraw_reward}}</b> 金币</li></ul><p><br/></p><h4>三、分销佣金</h4><p>好友在平台上消费或完成任务时，你可以获得一定比例的佣金收入：</p><ul><li><b>一级佣金：</b>好友消费金额的 <b>{{level1_commission_rate}}%</b></li><li><b>二级佣金：</b>二级好友消费金额的 <b>{{level2_commission_rate}}%</b></li></ul><p>佣金会自动计入你的账户，可在「邀请好友」页面查看佣金明细。</p><p><br/></p><h4>四、等级晋升</h4><p>累计佣金越高，你的分销等级越高，享受的权益也越多：</p><ul><li>普通会员 → 青铜代理 → 白银代理 → 黄金代理 → 铂金代理 → 钻石代理 → 星耀代理 → 王者代理</li></ul><p><br/></p><p style=\"color:#E62129;font-weight:bold;\">小技巧：多分享你的邀请码，建立自己的团队，被动收入更可观！</p>', '', 70, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (15, 2, '签到规则说明', '签到,打卡,补签,连续签到', '了解每日签到的奖励规则和补签机制', '', '<h3>每日签到规则</h3><p>每天签到是获取金币最简单的方式之一！</p><p><br/></p><h4>一、签到方式</h4><p>进入「首页 → 签到」页面，点击「立即签到」按钮即可完成当天签到。</p><p><br/></p><h4>二、签到奖励</h4><p>签到奖励分为以下几类：</p><ul><li><b>每日签到：</b>基础金币奖励，每天固定</li><li><b>连续签到加成：</b>连续签到天数越多，每日额外奖励越高</li><li><b>周签奖励：</b>连续签到满7天可获得周签额外奖励</li><li><b>月签奖励：</b>连续签到满整月可获得月签大额奖励</li></ul><p><br/></p><h4>三、补签规则</h4><ul><li>如果某天忘记签到，可以使用补签功能</li><li>补签需要消耗一定数量的金币</li><li>每月补签次数有限制（具体天数以签到页面显示为准）</li><li>只能补签最近几天漏签的日期，不支持跨月补签</li></ul><p><br/></p><h4>四、签到排行榜</h4><p>平台设有签到排行榜，展示连续签到天数最长的用户。坚持签到，说不定你就能上榜！</p><p><br/></p><h4>五、注意事项</h4><ul><li>每天只能签到一次，签到后无法撤销</li><li>签到时间以服务器时间为准</li><li>请勿使用第三方工具自动签到，违规将被风控系统处罚</li></ul>', '', 60, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (16, 2, '红包任务玩法', '红包,奖励,任务,福利', '了解红包任务的参与方式和奖励规则', '', '<h3>红包任务玩法</h3><p>红包任务是平台提供的额外金币获取途径，轻松好玩，奖励丰厚！</p><p><br/></p><h4>一、红包类型</h4><ul><li><b>定时红包：</b>每天固定时间点发放，先到先得</li><li><b>任务红包：</b>完成指定任务后解锁领取</li><li><b>随机红包：</b>不定期出现的惊喜红包</li></ul><p><br/></p><h4>二、参与方式</h4><ol><li>在首页或任务页面找到红包入口</li><li>点击红包进行抢夺</li><li>成功抢到后金币自动到账</li></ol><p><br/></p><h4>三、红包规则</h4><ul><li>每个红包有有效期，过期自动失效</li><li>每日抢红包次数有上限</li><li>两次抢红包之间有一定时间间隔</li><li>红包金额随机，运气越好奖励越多</li><li>单个红包最高可获 <b>{{red_packet_max_reward}}</b> 金币</li></ul><p><br/></p><h4>四、温馨提示</h4><p>红包数量有限，看到红包记得第一时间点击领取哦！</p>', '', 50, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (17, 2, '账户安全与风控说明', '安全,封号,风控,违规,申诉', '了解平台风控规则和账户安全注意事项', '', '<h3>账户安全与风控说明</h3><p>为维护平台健康生态，保障所有用户的公平权益，平台设有完善的风控体系。</p><p><br/></p><h4>一、风控规则</h4><p>以下行为会被风控系统检测并处罚：</p><ul><li>使用模拟器、脚本、外挂等自动化工具</li><li>使用VPN/代理/修改器等作弊手段</li><li>同一设备或IP注册多个账号</li><li>恶意刷金币、刷提现等行为</li><li>利用系统漏洞获取不当利益</li></ul><p><br/></p><h4>二、处罚措施</h4><ul><li><b>轻度违规（风控分数达到 <b>{{risk_freeze_threshold}}</b> 分）：</b>警告 + 冻结部分功能（如提现）</li><li><b>中度违规（风控分数达到 <b>{{risk_ban_threshold}}</b> 分）：</b>冻结账户，限制操作</li><li><b>重度违规：</b>永久封禁账号</li></ul><p><br/></p><h4>三、账户安全建议</h4><ol><li>绑定手机号，提高账户安全性</li><li>不要将账号借给他人使用</li><li>不要在非官方渠道下载App</li><li>定期修改密码</li><li>发现异常及时联系客服</li></ol><p><br/></p><h4>四、申诉方式</h4><p>如果你的账户被误封或对处罚有异议，可以通过以下方式申诉：</p><ul><li>在App内联系在线客服</li><li>发送邮件至客服邮箱（详见联系客服页面）</li><li>提供你的用户ID和相关说明，客服会在1-3个工作日内处理</li></ul>', '', 40, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (18, 2, '常见问题FAQ', 'FAQ,常见问题,疑问,解答', '用户常见问题汇总与解答', '', '<h3>常见问题FAQ</h3><p><br/></p><h4>Q1：如何注册账号？</h4><p>A：打开App点击登录页面，支持微信一键登录和手机号登录两种方式。新用户注册成功可获 <b>{{new_user_coin}}</b> 金币新人奖励。</p><p><br/></p><h4>Q2：忘记密码怎么办？</h4><p>A：在登录页面点击「忘记密码」，通过手机验证码重置密码即可。</p><p><br/></p><h4>Q3：金币有有效期吗？</h4><p>A：金币没有有效期，可以一直累积使用，不会被清零。</p><p><br/></p><h4>Q4：为什么签到奖励不一样？</h4><p>A：签到奖励与连续签到天数有关，连续签到天数越长奖励越丰厚。中断签到后连续天数会重新计算。</p><p><br/></p><h4>Q5：邀请码在哪里查看？</h4><p>A：进入「我的」页面，在用户名下方即可看到你的邀请码，点击可以复制。每成功邀请一位好友注册可获得 <b>{{invite_register_reward}}</b> 金币。</p><p><br/></p><h4>Q6：提现多久能到账？</h4><p>A：<b>{{auto_audit_amount}}</b> 元以下自动审核后即时到账。<b>{{manual_audit_amount}}</b> 元以上需要人工审核，一般在1-3个工作日内到账。</p><p><br/></p><h4>Q7：为什么我无法提现？</h4><p>A：可能的原因有：①金币余额不足（最低需 <b>{{min_withdraw}}</b> 元）；②新账号还在注册保护期（需注册满 <b>{{new_user_withdraw_days}}</b> 天）；③账户存在异常被冻结。请根据具体提示进行操作。</p><p><br/></p><h4>Q8：如何联系客服？</h4><p>A：在「我的」页面中点击「联系客服」即可查看客服联系方式和在线咨询入口。</p><p><br/></p><h4>Q9：可以修改绑定的手机号吗？</h4><p>A：可以，在「我的 → 系统设置」中可以更换绑定的手机号，需要验证原手机号和新手机号。</p><p><br/></p><h4>Q10：金币兑换比例是多少？</h4><p>A：当前兑换比例为 <b>{{coin_rate}}</b> 金币 = 1 元，具体以钱包页面显示为准。</p><p><br/></p><h4>Q11：每日金币获取有上限吗？</h4><p>A：有上限的。每日金币获取上限为 <b>{{daily_coin_limit}}</b> 金币，每小时上限 <b>{{hourly_coin_limit}}</b> 金币。每日最多可观看 <b>{{daily_video_limit}}</b> 个视频。</p><p><br/></p><h4>Q12：分销等级有什么用？</h4><p>A：分销等级根据累计佣金自动升级，等级越高代表你的推广能力越强。一级佣金比例为 <b>{{level1_commission_rate}}%</b>，二级佣金比例为 <b>{{level2_commission_rate}}%</b>。</p><p><br/></p><p style=\"color:#999;text-align:center;\">以上是常见问题汇总，如未解决您的问题请联系在线客服</p>', '', 30, 1, 1775208668, 1775208668, NULL);
INSERT INTO `advn_singlepage` VALUES (19, 3, '用户协议', '用户协议,服务条款,使用条款,注册协议', '平台用户服务协议', '', '<h2 style=\"text-align:center;color:#E62129;\">用户服务协议</h2>\n<p style=\"text-align:center;color:#999;font-size:12px;\">更新日期：2026年7月17日</p>\n<p><br/></p>\n<p><b>尊敬的用户，欢迎使用本平台！</b></p>\n<p>在您使用本平台提供的各项服务之前，请您仔细阅读并充分理解本《用户服务协议》（以下简称\"本协议\"）。您一旦注册、登录、使用本平台服务，即视为您已阅读并同意本协议的全部内容。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">一、总则</h3>\n<p>1.1 本协议是您与平台运营方（以下简称\"平台\"）之间关于使用平台各项服务所订立的协议。</p>\n<p>1.2 平台有权根据法律法规变化及业务发展需要，对本协议进行修订。修订后的协议将在平台内公布，若您继续使用平台服务，即视为同意修订后的协议。</p>\n<p>1.3 本协议中与您的权益密切相关的条款，已采用加粗等方式显著标识，请您特别注意。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">二、账号注册与管理</h3>\n<p>2.1 您需使用真实手机号或微信授权等方式注册账号，并对账号信息的真实性、合法性负责。</p>\n<p>2.2 每位用户仅可注册一个账号，禁止一人多号、虚假注册。</p>\n<p>2.3 您应妥善保管账号和密码，因您自身原因导致账号被盗、密码泄露等，由您自行承担责任。</p>\n<p>2.4 您不得将账号出借、转让、出售给他人使用。</p>\n<p>2.5 如发现账号被他人冒用或存在安全风险，请立即联系平台客服。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">三、用户行为规范</h3>\n<p>3.1 您在使用平台服务时，应遵守国家法律法规，不得利用平台从事违法违规活动。</p>\n<p>3.2 <b>禁止行为包括但不限于：</b></p>\n<ul>\n<li>使用模拟器、脚本、外挂、自动化工具等作弊手段获取金币或奖励；</li>\n<li>利用系统漏洞获取不当利益；</li>\n<li>恶意刷金币、刷提现、虚假签到等行为；</li>\n<li>发布违法违规、虚假、侵权、恶意的内容；</li>\n<li>干扰平台正常运营，影响其他用户使用；</li>\n<li>同一设备或IP注册多个账号；</li>\n<li>使用VPN、代理等手段规避平台风控规则。</li>\n</ul>\n<p>3.3 如您违反上述规定，平台有权视情节轻重采取以下措施：</p>\n<ul>\n<li>警告、限制功能（如冻结提现）；</li>\n<li>冻结账号；</li>\n<li>永久封禁账号；</li>\n<li>扣除违规所得金币/佣金；</li>\n<li>依法追究法律责任。</li>\n</ul>\n<p><br/></p>\n<h3 style=\"color:#333;\">四、金币与奖励</h3>\n<p>4.1 平台金币为虚拟权益，仅限在本平台内使用，不可转让、兑换现金或提现至第三方账户。</p>\n<p>4.2 金币获取方式包括但不限于：每日签到、观看视频、邀请好友、红包活动等，具体规则以平台公告为准。</p>\n<p>4.3 平台有权根据运营需要调整金币获取规则、兑换比例及每日上限，调整前将通过公告通知。</p>\n<p>4.4 <b>金币提现规则：</b></p>\n<ul>\n<li>金币可按平台公示的兑换比例兑换为人民币，提现至微信零钱；</li>\n<li>最低提现金额及每日提现次数限制以平台设置为准；</li>\n<li>新注册用户需满足注册天数要求后方可提现；</li>\n<li>提现审核通过后，金额将在合理时间内到账；</li>\n<li>平台有权对异常提现申请进行审核或拒绝。</li>\n</ul>\n<p><br/></p>\n<h3 style=\"color:#333;\">五、分销与邀请</h3>\n<p>5.1 用户可通过邀请码、邀请链接等方式邀请好友注册，获得邀请奖励和分销佣金。</p>\n<p>5.2 分销佣金规则详见《分销规则》，平台有权根据运营情况调整佣金比例。</p>\n<p>5.3 禁止通过虚假邀请、刷单等方式骗取佣金，一经发现将取消佣金并封禁账号。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">六、知识产权</h3>\n<p>6.1 平台的所有内容（包括但不限于文字、图片、音频、视频、软件、界面设计等）均受知识产权法律保护。</p>\n<p>6.2 未经平台书面许可，您不得复制、传播、修改、创造衍生作品或进行商业使用。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">七、免责声明</h3>\n<p>7.1 因不可抗力（如自然灾害、网络故障、政策变化等）导致服务中断的，平台不承担责任。</p>\n<p>7.2 因用户自身原因（如网络问题、设备故障等）导致无法使用服务的，平台不承担责任。</p>\n<p>7.3 平台提供的信息仅供参考，不构成任何投资建议或承诺。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">八、协议终止</h3>\n<p>8.1 您可以随时注销账号并停止使用平台服务。注销后，账号内的金币、佣金等虚拟资产将被清零且不可恢复。</p>\n<p>8.2 如您严重违反本协议，平台有权单方面终止向您提供服务，并保留追究法律责任的权利。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">九、其他条款</h3>\n<p>9.1 本协议的解释和执行适用中华人民共和国法律。</p>\n<p>9.2 如本协议中的任何条款被认定为无效或不可执行，不影响其他条款的效力。</p>\n<p>9.3 因本协议引起的争议，双方应友好协商解决；协商不成的，任何一方可向平台所在地有管辖权的人民法院提起诉讼。</p>\n<p><br/></p>\n<p style=\"color:#999;font-size:12px;text-align:right;\">—— 平台运营团队</p>', 'user-agreement', 100, 1, 1775209574, 1775209574, NULL);
INSERT INTO `advn_singlepage` VALUES (20, 3, '隐私协议', '隐私协议,隐私政策,个人信息保护,数据安全', '平台隐私保护政策', '', '<h2 style=\"text-align:center;color:#E62129;\">隐私保护政策</h2>\n<p style=\"text-align:center;color:#999;font-size:12px;\">更新日期：2026年7月17日</p>\n<p><br/></p>\n<p><b>平台深知个人信息对您的重要性，我们将按照法律法规的规定，保护您的个人信息及隐私安全。</b></p>\n<p>我们制定本《隐私保护政策》以帮助您了解我们如何收集、使用、存储和保护您的个人信息。请您在使用我们的服务前，仔细阅读并充分理解本政策。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">一、我们收集的信息</h3>\n<p>1.1 <b>注册信息：</b>当您注册账号时，我们会收集您的手机号码、微信授权信息（昵称、头像等）。</p>\n<p>1.2 <b>个人资料：</b>当您完善个人资料时，我们会收集您设置的昵称、头像、性别、生日、个人简介等信息。</p>\n<p>1.3 <b>设备信息：</b>我们会自动收集您的设备型号、操作系统版本、设备标识符（IDFA/IMEI等）、IP地址、网络类型等信息，用于保障账号安全和优化服务体验。</p>\n<p>1.4 <b>行为信息：</b>我们会记录您在平台上的操作行为，包括但不限于签到记录、视频观看记录、提现记录、邀请关系等，用于提供服务和风控管理。</p>\n<p>1.5 <b>提现信息：</b>当您申请提现时，需要提供微信账户信息用于打款，该信息由微信平台处理，我们仅传递必要的打款指令。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">二、我们如何使用您的信息</h3>\n<p>2.1 <b>提供核心服务：</b>用于账号注册、身份验证、金币发放与提现、邀请关系绑定等。</p>\n<p>2.2 <b>安全保障：</b>用于风控管理、防止作弊和欺诈行为、账号安全防护。</p>\n<p>2.3 <b>服务优化：</b>用于分析用户行为，优化产品功能和用户体验。</p>\n<p>2.4 <b>消息通知：</b>用于向您发送系统通知、活动通知等（您可以关闭推送通知）。</p>\n<p>2.5 <b>法律合规：</b>法律法规要求或监管部门要求的其他用途。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">三、信息的存储与保护</h3>\n<p>3.1 <b>存储地点：</b>您的个人信息存储在中华人民共和国境内的服务器上。</p>\n<p>3.2 <b>存储期限：</b>我们仅在为您提供服务所必需的期限内保留您的个人信息。账号注销后，我们将删除或匿名化处理您的个人信息，法律法规另有规定的除外。</p>\n<p>3.3 <b>安全措施：</b>我们采用行业标准的安全技术措施保护您的信息，包括但不限于：</p>\n<ul>\n<li>SSL/TLS 加密传输；</li>\n<li>数据加密存储；</li>\n<li>严格的访问权限控制；</li>\n<li>定期的安全评估和审计。</li>\n</ul>\n<p>3.4 尽管我们采取了合理的安全措施，但互联网环境并非绝对安全。如发生个人信息安全事件，我们将及时通知您并采取补救措施。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">四、信息的共享与披露</h3>\n<p>4.1 <b>我们不会向第三方出售您的个人信息。</b></p>\n<p>4.2 在以下情况下，我们可能会共享您的信息：</p>\n<ul>\n<li><b>服务合作伙伴：</b>如微信支付等，仅共享完成服务所必需的最少信息；</li>\n<li><b>法律要求：</b>根据法律法规、监管要求、诉讼或政府部门的合法要求；</li>\n<li><b>紧急情况：</b>为保护您或公众的人身、财产安全所必需。</li>\n</ul>\n<p>4.3 如发生合并、收购、资产转让等，我们会要求新的持有方继续受本隐私政策的约束。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">五、您的权利</h3>\n<p>5.1 <b>查询权：</b>您可以在\"个人资料\"页面查看您的个人信息。</p>\n<p>5.2 <b>更正权：</b>您可以在\"个人资料\"页面修改您的昵称、头像、性别、生日、简介等信息。</p>\n<p>5.3 <b>删除权：</b>您可以申请注销账号，注销后我们将删除您的个人信息（法律法规要求保留的除外）。</p>\n<p>5.4 <b>撤回同意权：</b>您可以在设备设置中关闭相关权限（如位置、相册等），这可能影响部分功能的使用。</p>\n<p>5.5 <b>投诉权：</b>如您对我们的个人信息处理有任何疑问或投诉，可以通过平台客服渠道联系我们。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">六、未成年人保护</h3>\n<p>6.1 我们非常重视未成年人的个人信息保护。</p>\n<p>6.2 如果您是未满18周岁的未成年人，请在监护人的陪同下阅读本政策，并在取得监护人同意后使用我们的服务。</p>\n<p>6.3 我们不会主动收集未满14周岁儿童的个人信息。如我们发现在未取得监护人同意的情况下收集了儿童信息，将及时删除。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">七、Cookie 和类似技术</h3>\n<p>7.1 我们使用 Cookie 和类似技术来改善您的使用体验，例如记住您的登录状态。</p>\n<p>7.2 您可以通过浏览器设置拒绝或删除 Cookie，但这可能影响您使用平台的部分功能。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">八、隐私政策的更新</h3>\n<p>8.1 我们可能会不时更新本隐私政策。更新后的政策将在平台内公布。</p>\n<p>8.2 如变更内容对您的权利产生重大影响，我们会通过弹窗、站内信等方式显著通知您。</p>\n<p>8.3 在您继续使用我们的服务后，即视为同意受更新后的隐私政策约束。</p>\n<p><br/></p>\n<h3 style=\"color:#333;\">九、联系我们</h3>\n<p>如您对本隐私政策有任何疑问、意见或建议，可通过以下方式联系我们：</p>\n<ul>\n<li>在App内联系在线客服；</li>\n<li>发送邮件至平台客服邮箱。</li>\n</ul>\n<p><br/></p>\n<p style=\"color:#999;font-size:12px;text-align:right;\">—— 平台运营团队</p>', 'privacy-policy', 90, 1, 1775209574, 1775209574, NULL);

-- ----------------------------
-- Table structure for advn_singlepage_category
-- ----------------------------
DROP TABLE IF EXISTS `advn_singlepage_category`;
CREATE TABLE `advn_singlepage_category`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '分类名称',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '分类描述',
  `weigh` int NOT NULL DEFAULT 0 COMMENT '权重(排序)',
  `status` tinyint(1) NOT NULL DEFAULT 1 COMMENT '状态: 1=启用, 0=禁用',
  `createtime` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '创建时间',
  `updatetime` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '更新时间',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '单页分类表' ROW_FORMAT = Dynamic;

