DROP TABLE IF EXISTS `advn_task_audit_log`;
CREATE TABLE `advn_task_audit_log`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `task_id` int UNSIGNED NOT NULL COMMENT '任务ID',
  `participation_id` bigint UNSIGNED NOT NULL COMMENT '参与记录ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `action` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '操作: submit/audit_pass/audit_reject/reward',
  `old_status` tinyint UNSIGNED NULL DEFAULT NULL COMMENT '原状态',
  `new_status` tinyint UNSIGNED NULL DEFAULT NULL COMMENT '新状态',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `operator_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '操作者类型: system/admin/user',
  `operator_id` int UNSIGNED NULL DEFAULT NULL COMMENT '操作者ID',
  `createtime` int UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_participation_id`(`participation_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '任务审核日志表' ROW_FORMAT = Dynamic;

