-- ----------------------------
-- Table structure for advn_task_message
-- ----------------------------
DROP TABLE IF EXISTS `advn_task_message`;
CREATE TABLE `advn_task_message`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `task_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '关联任务ID',
  `type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'task_push' COMMENT '消息类型:task_push=任务推送,reward=奖励通知,system=系统通知',
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '消息标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '消息内容',
  `message_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '消息详细数据JSON',
  `status` tinyint(1) NOT NULL DEFAULT 0 COMMENT '状态:0=待发送,1=已发送,2=已过期',
  `target_users` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '目标用户ID列表JSON,空为全部',
  `send_time` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '发送时间',
  `expire_time` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '过期时间',
  `createtime` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '创建时间',
  `updatetime` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_send_time`(`send_time` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '任务消息推送表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_task_message
-- ----------------------------

-- ----------------------------
-- Table structure for advn_task_participation
-- ----------------------------
DROP TABLE IF EXISTS `advn_task_participation`;
CREATE TABLE `advn_task_participation`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `task_id` int UNSIGNED NOT NULL COMMENT '红包任务ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `order_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '参与订单号',
  `task_type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '任务类型',
  `task_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '任务名称快照',
  `task_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '任务链接快照',
  `status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '状态: 0=已领取待完成, 1=已完成待审核, 2=审核通过待发放, 3=已发放, 4=审核拒绝, 5=已过期, 6=已取消',
  `start_time` int UNSIGNED NULL DEFAULT NULL COMMENT '开始时间',
  `end_time` int UNSIGNED NULL DEFAULT NULL COMMENT '完成时间',
  `duration` int UNSIGNED NULL DEFAULT 0 COMMENT '实际耗时(秒)',
  `progress` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '完成进度(%)',
  `audit_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'auto' COMMENT '审核方式',
  `audit_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '审核状态: 0=待审核, 1=通过, 2=拒绝',
  `audit_time` int UNSIGNED NULL DEFAULT NULL COMMENT '审核时间',
  `audit_admin_id` int UNSIGNED NULL DEFAULT NULL COMMENT '审核管理员ID',
  `audit_admin_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核管理员名称',
  `audit_remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核备注',
  `reject_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '拒绝原因',
  `reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '奖励金币',
  `reward_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '发放状态: 0=未发放, 1=已发放',
  `reward_time` int UNSIGNED NULL DEFAULT NULL COMMENT '发放时间',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'IP地址',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备ID',
  `device_info` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '设备信息(JSON)',
  `app_version` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'APP版本',
  `platform` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '平台: ios/android/h5',
  `screenshot_urls` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '截图URLs(JSON数组)',
  `proof_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '证明数据(JSON)',
  `extra_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '额外数据(JSON)',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_no`(`order_no` ASC) USING BTREE,
  INDEX `idx_task_id`(`task_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_user_task`(`user_id` ASC, `task_id` ASC) USING BTREE,
  INDEX `idx_audit_status`(`audit_status` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE,
  INDEX `idx_device_id`(`device_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '任务参与记录表' ROW_FORMAT = Dynamic;

