-- ----------------------------
-- Table structure for advn_user_behavior
-- ----------------------------
DROP TABLE IF EXISTS `advn_user_behavior`;
CREATE TABLE `advn_user_behavior`  (
  `id` bigint UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `behavior_type` enum('login','video_watch','task_complete','withdraw','redpacket_grab','invite','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '行为类型',
  `behavior_action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '行为动作',
  `target_id` int UNSIGNED NULL DEFAULT NULL COMMENT '目标ID',
  `target_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '目标类型',
  `device_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '设备ID',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'IP地址',
  `user_agent` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'User-Agent',
  `duration` int NOT NULL DEFAULT 0 COMMENT '行为持续时间(秒)',
  `extra_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '额外数据JSON',
  `risk_flag` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否标记为风险',
  `risk_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '风险原因',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_behavior_type`(`behavior_type` ASC) USING BTREE,
  INDEX `idx_behavior_action`(`behavior_action` ASC) USING BTREE,
  INDEX `idx_createtime`(`createtime` ASC) USING BTREE,
  INDEX `idx_device_id`(`device_id` ASC) USING BTREE,
  INDEX `idx_ip`(`ip` ASC) USING BTREE,
  INDEX `idx_risk_flag`(`risk_flag` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户行为记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_user_behavior
-- ----------------------------

-- ----------------------------
-- Table structure for advn_user_behavior_archive
-- ----------------------------
DROP TABLE IF EXISTS `advn_user_behavior_archive`;
CREATE TABLE `advn_user_behavior_archive`  (
  `id` bigint UNSIGNED NOT NULL COMMENT '主键',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `behavior_type` enum('login','video_watch','task_complete','withdraw','redpacket_grab','invite','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '行为类型',
  `behavior_action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '行为动作',
  `target_id` int UNSIGNED NULL DEFAULT NULL COMMENT '目标ID',
  `target_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '目标类型',
  `device_id` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '设备ID',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'IP地址',
  `user_agent` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT 'User-Agent',
  `duration` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '行为持续时间(秒)',
  `extra_data` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '额外数据JSON',
  `risk_flag` tinyint UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否标记为风险',
  `risk_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT '' COMMENT '风险原因',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_behavior_type`(`behavior_type` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户行为记录归档表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_user_behavior_archive
-- ----------------------------

-- ----------------------------
-- Table structure for advn_user_behavior_stat
-- ----------------------------
DROP TABLE IF EXISTS `advn_user_behavior_stat`;
CREATE TABLE `advn_user_behavior_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `stat_date` date NOT NULL COMMENT '统计日期',
  `video_watch_count` int NOT NULL DEFAULT 0 COMMENT '视频观看次数',
  `video_watch_duration` int NOT NULL DEFAULT 0 COMMENT '视频观看总时长(秒)',
  `video_skip_count` int NOT NULL DEFAULT 0 COMMENT '视频跳过次数',
  `video_coin_earned` int NOT NULL DEFAULT 0 COMMENT '视频获得金币',
  `task_complete_count` int NOT NULL DEFAULT 0 COMMENT '任务完成次数',
  `task_coin_earned` int NOT NULL DEFAULT 0 COMMENT '任务获得金币',
  `withdraw_count` int NOT NULL DEFAULT 0 COMMENT '提现次数',
  `withdraw_amount` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT '提现金额',
  `redpacket_grab_count` int NOT NULL DEFAULT 0 COMMENT '抢红包次数',
  `redpacket_coin_earned` int NOT NULL DEFAULT 0 COMMENT '红包获得金币',
  `invite_count` int NOT NULL DEFAULT 0 COMMENT '邀请人数',
  `invite_reward` decimal(15, 2) NOT NULL DEFAULT 0.00 COMMENT '邀请奖励',
  `login_count` int NOT NULL DEFAULT 0 COMMENT '登录次数',
  `active_duration` int NOT NULL DEFAULT 0 COMMENT '活跃时长(秒)',
  `device_change_count` int NOT NULL DEFAULT 0 COMMENT '设备切换次数',
  `ip_change_count` int NOT NULL DEFAULT 0 COMMENT 'IP切换次数',
  `violation_count` int NOT NULL DEFAULT 0 COMMENT '违规次数',
  `risk_score_add` int NOT NULL DEFAULT 0 COMMENT '新增风险分',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id` ASC, `stat_date` ASC) USING BTREE,
  INDEX `idx_stat_date`(`stat_date` ASC) USING BTREE,
  INDEX `idx_violation_count`(`violation_count` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户行为统计表' ROW_FORMAT = Dynamic;

