DROP TABLE IF EXISTS `advn_user_commission_stat`;
CREATE TABLE `advn_user_commission_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '统计ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `total_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '累计佣金(元)',
  `total_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '累计金币',
  `level1_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '一级佣金(元)',
  `level2_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '二级佣金(元)',
  `withdraw_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '提现分佣收益(元)',
  `video_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '视频分佣收益(元)',
  `red_packet_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '红包分佣收益(元)',
  `game_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '游戏分佣收益(元)',
  `other_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '其他分佣收益(元)',
  `today_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '今日佣金(元)',
  `today_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '今日金币',
  `yesterday_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '昨日佣金(元)',
  `week_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '本周佣金(元)',
  `month_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '本月佣金(元)',
  `pending_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '待结算佣金(元)',
  `frozen_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '冻结佣金(元)',
  `canceled_commission` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '已取消佣金(元)',
  `withdraw_count` int UNSIGNED NULL DEFAULT 0 COMMENT '提现分佣次数',
  `video_count` int UNSIGNED NULL DEFAULT 0 COMMENT '视频分佣次数',
  `red_packet_count` int UNSIGNED NULL DEFAULT 0 COMMENT '红包分佣次数',
  `game_count` int UNSIGNED NULL DEFAULT 0 COMMENT '游戏分佣次数',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_total_commission`(`total_commission` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户佣金统计表' ROW_FORMAT = Dynamic;

