-- Table structure for advn_user_daily_reward_stat
-- ----------------------------
DROP TABLE IF EXISTS `advn_user_daily_reward_stat`;
CREATE TABLE `advn_user_daily_reward_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `date_key` date NOT NULL COMMENT '日期',
  `video_watch_count` int UNSIGNED NULL DEFAULT 0 COMMENT '观看视频数',
  `video_watch_duration` int UNSIGNED NULL DEFAULT 0 COMMENT '观看时长(秒)',
  `video_reward_count` int UNSIGNED NULL DEFAULT 0 COMMENT '获得奖励次数',
  `video_reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '获得金币',
  `task_reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '任务奖励',
  `other_reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '其他奖励',
  `total_reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '总获得金币',
  `createtime` int UNSIGNED NULL DEFAULT NULL,
  `updatetime` int UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_date`(`user_id` ASC, `date_key` ASC) USING BTREE,
  INDEX `idx_date_key`(`date_key` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户每日收益统计表' ROW_FORMAT = Dynamic;

