DROP TABLE IF EXISTS `advn_user_red_packet_accumulate_202602`;
CREATE TABLE `advn_user_red_packet_accumulate_202602`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `user_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '用户ID',
  `task_id` int UNSIGNED NOT NULL DEFAULT 0 COMMENT '任务ID',
  `base_amount` int UNSIGNED NULL DEFAULT 0 COMMENT '基础金额',
  `accumulate_amount` int UNSIGNED NULL DEFAULT 0 COMMENT '累计金额',
  `total_amount` int UNSIGNED NULL DEFAULT 0 COMMENT '总金额(基础+累计)',
  `click_count` int UNSIGNED NULL DEFAULT 1 COMMENT '点击次数',
  `is_new_user` tinyint(1) NULL DEFAULT 0 COMMENT '是否新用户',
  `is_collected` tinyint(1) NULL DEFAULT 0 COMMENT '是否已领取',
  `collect_time` bigint NULL DEFAULT NULL COMMENT '领取时间',
  `createtime` bigint NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` bigint NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `user_task`(`user_id` ASC, `task_id` ASC) USING BTREE,
  INDEX `user_id`(`user_id` ASC) USING BTREE,
  INDEX `task_id`(`task_id` ASC) USING BTREE,
  INDEX `is_collected`(`is_collected` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 550 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户红包累计记录表' ROW_FORMAT = Dynamic;

