-- ----------------------------
-- Table structure for advn_user_risk_score
-- ----------------------------
DROP TABLE IF EXISTS `advn_user_risk_score`;
CREATE TABLE `advn_user_risk_score`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `total_score` int NOT NULL DEFAULT 0 COMMENT '总风险分值(0-1000)',
  `risk_level` enum('safe','low','medium','high','dangerous') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'safe' COMMENT '风险等级',
  `video_score` int NOT NULL DEFAULT 0 COMMENT '视频相关风险分',
  `task_score` int NOT NULL DEFAULT 0 COMMENT '任务相关风险分',
  `withdraw_score` int NOT NULL DEFAULT 0 COMMENT '提现相关风险分',
  `redpacket_score` int NOT NULL DEFAULT 0 COMMENT '红包相关风险分',
  `invite_score` int NOT NULL DEFAULT 0 COMMENT '邀请相关风险分',
  `global_score` int NOT NULL DEFAULT 0 COMMENT '全局风险分',
  `violation_count` int NOT NULL DEFAULT 0 COMMENT '违规次数',
  `last_violation_time` int UNSIGNED NULL DEFAULT NULL COMMENT '最后违规时间',
  `ban_expire_time` int UNSIGNED NULL DEFAULT NULL COMMENT '封禁到期时间',
  `freeze_expire_time` int UNSIGNED NULL DEFAULT NULL COMMENT '冻结到期时间',
  `status` enum('normal','frozen','banned') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'normal' COMMENT '状态',
  `score_history` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '评分历史JSON',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_risk_level`(`risk_level` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_ban_expire`(`ban_expire_time` ASC) USING BTREE,
  INDEX `idx_freeze_expire`(`freeze_expire_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 63 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '用户风控评分表' ROW_FORMAT = Dynamic;

