-- ----------------------------
-- Table structure for advn_video
-- ----------------------------
DROP TABLE IF EXISTS `advn_video`;
CREATE TABLE `advn_video`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '视频ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '发布者ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '视频标题',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '视频描述',
  `cover_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '封面图URL',
  `video_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '视频URL',
  `duration` int UNSIGNED NULL DEFAULT 0 COMMENT '视频时长(秒)',
  `width` int UNSIGNED NULL DEFAULT 0 COMMENT '视频宽度(px)',
  `height` int UNSIGNED NULL DEFAULT 0 COMMENT '视频高度(px)',
  `file_size` bigint UNSIGNED NULL DEFAULT 0 COMMENT '文件大小(字节)',
  `format` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '视频格式: mp4/mov/avi',
  `category_id` int UNSIGNED NULL DEFAULT NULL COMMENT '分类ID',
  `collection_id` int UNSIGNED NULL DEFAULT NULL COMMENT '所属合集ID',
  `episode` int UNSIGNED NULL DEFAULT 1 COMMENT '集数序号',
  `tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '标签(JSON数组)',
  `reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 100.00 COMMENT '观看奖励金币',
  `reward_duration` int UNSIGNED NULL DEFAULT 30 COMMENT '奖励所需观看时长(秒)',
  `reward_enabled` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '是否开启奖励: 0=否, 1=是',
  `reward_rule_id` int UNSIGNED NULL DEFAULT NULL COMMENT '收益规则ID',
  `view_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '播放量',
  `like_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '点赞数',
  `comment_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '评论数',
  `share_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '分享数',
  `collect_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '收藏数',
  `reward_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '奖励人数',
  `reward_coin_total` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '已发放奖励金币',
  `status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '状态: 0=待审核, 1=已发布, 2=已下架, 3=已封禁, 4=草稿',
  `is_original` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '是否原创: 0=转载, 1=原创',
  `is_recommend` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否推荐: 0=否, 1=是',
  `is_hot` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否热门: 0=否, 1=是',
  `sort` int UNSIGNED NULL DEFAULT 0 COMMENT '排序权重',
  `audit_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '审核状态: 0=待审核, 1=通过, 2=拒绝',
  `audit_admin_id` int UNSIGNED NULL DEFAULT NULL COMMENT '审核管理员ID',
  `audit_time` int UNSIGNED NULL DEFAULT NULL COMMENT '审核时间',
  `audit_remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核备注',
  `reject_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '拒绝原因',
