  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间戳',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间戳',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_category_id`(`category_id` ASC) USING BTREE,
