DROP TABLE IF EXISTS `advn_video_collection`;
CREATE TABLE `advn_video_collection`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '合集ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '合集标题',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '合集描述',
  `cover_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '封面图URL',
  `video_count` int UNSIGNED NULL DEFAULT 0 COMMENT '视频数量',
  `total_duration` int UNSIGNED NULL DEFAULT 0 COMMENT '总时长(秒)',
  `view_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '播放量',
  `reward_enabled` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '是否开启奖励',
  `reward_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'per_video' COMMENT '奖励方式: per_video=每集, complete=看完合集, progressive=递进',
  `reward_coin_per_video` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '每集奖励金币',
  `reward_coin_complete` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '看完合集奖励',
