  `sort` int UNSIGNED NULL DEFAULT 0 COMMENT '排序',
  `createtime` int UNSIGNED NULL DEFAULT NULL,
  `updatetime` int UNSIGNED NULL DEFAULT NULL,
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '视频合集表' ROW_FORMAT = Dynamic;

