-- ----------------------------
-- Table structure for advn_video_reward_rule
-- ----------------------------
DROP TABLE IF EXISTS `advn_video_reward_rule`;
CREATE TABLE `advn_video_reward_rule`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '规则ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '规则名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '规则代码(唯一标识)',
  `description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '规则描述',
  `scope_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'global' COMMENT '适用范围: global=全局, category=分类, video=单视频, collection=合集',
  `scope_id` int UNSIGNED NULL DEFAULT NULL COMMENT '范围ID(分类ID/视频ID/合集ID)',
  `reward_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'fixed' COMMENT '奖励类型: fixed=固定, random=随机, progressive=递进',
  `reward_coin` decimal(18, 2) UNSIGNED NOT NULL DEFAULT 0.00 COMMENT '固定奖励金币',
  `reward_min` decimal(18, 2) UNSIGNED NULL DEFAULT NULL COMMENT '最小奖励(随机时)',
  `reward_max` decimal(18, 2) UNSIGNED NULL DEFAULT NULL COMMENT '最大奖励(随机时)',
  `condition_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'complete' COMMENT '条件类型: complete=看完, duration=时长, count=集数',
  `watch_progress` tinyint UNSIGNED NULL DEFAULT 95 COMMENT '观看进度(%), 达到此进度视为看完',
  `watch_duration` int UNSIGNED NULL DEFAULT 0 COMMENT '需要观看时长(秒)',
  `watch_duration_ratio` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '时长占比(%)',
  `watch_count` int UNSIGNED NULL DEFAULT 0 COMMENT '需要观看集数',
  `watch_count_reward_per` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否每集奖励: 0=否, 1=是',
  `daily_limit` int UNSIGNED NULL DEFAULT 0 COMMENT '每日奖励次数限制(0=不限)',
  `daily_limit_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'user' COMMENT '限制维度: user=用户, video=视频, rule=规则',
  `total_limit` int UNSIGNED NULL DEFAULT 0 COMMENT '总奖励次数限制(0=不限)',
  `user_level_min` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '最低用户等级',
  `user_level_max` tinyint UNSIGNED NULL DEFAULT 255 COMMENT '最高用户等级(255=不限)',
  `new_user_only` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '仅限新用户: 0=否, 1=是',
  `new_user_days` int UNSIGNED NULL DEFAULT 7 COMMENT '新用户定义(注册天数)',
  `start_time` int UNSIGNED NULL DEFAULT NULL COMMENT '规则生效开始时间',
  `end_time` int UNSIGNED NULL DEFAULT NULL COMMENT '规则生效结束时间',
  `priority` int UNSIGNED NULL DEFAULT 0 COMMENT '优先级(越大越高)',
  `status` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '状态: 0=禁用, 1=启用',
  `sort` int UNSIGNED NULL DEFAULT 0 COMMENT '排序',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  `deletetime` int UNSIGNED NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_code`(`code` ASC) USING BTREE,
  INDEX `idx_scope`(`scope_type` ASC, `scope_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_priority`(`priority` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '视频收益规则表' ROW_FORMAT = Dynamic;

