DROP TABLE IF EXISTS `advn_video_watch_record`;
CREATE TABLE `advn_video_watch_record`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `video_id` int UNSIGNED NOT NULL COMMENT '视频ID',
  `collection_id` int UNSIGNED NULL DEFAULT NULL COMMENT '合集ID',
  `watch_duration` int UNSIGNED NULL DEFAULT 0 COMMENT '累计观看时长(秒)',
  `watch_progress` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '观看进度(%)',
  `watch_count` int UNSIGNED NULL DEFAULT 0 COMMENT '观看次数',
  `last_position` int UNSIGNED NULL DEFAULT 0 COMMENT '上次观看位置(秒)',
  `is_completed` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '是否看完: 0=否, 1=是',
  `complete_time` int UNSIGNED NULL DEFAULT NULL COMMENT '完成时间',
  `reward_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '奖励状态: 0=未领取, 1=已领取, 2=已失效',
  `reward_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '获得金币',
  `reward_time` int UNSIGNED NULL DEFAULT NULL COMMENT '奖励时间',
  `reward_rule_id` int UNSIGNED NULL DEFAULT NULL COMMENT '使用的规则ID',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '观看IP',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备ID',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '首次观看时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '最后观看时间',
  `date_key` date NULL DEFAULT NULL COMMENT '日期键(便于统计)',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_video`(`user_id` ASC, `video_id` ASC) USING BTREE,
  INDEX `idx_video_id`(`video_id` ASC) USING BTREE,
  INDEX `idx_collection_id`(`collection_id` ASC) USING BTREE,
  INDEX `idx_reward_status`(`reward_status` ASC) USING BTREE,
  INDEX `idx_user_date`(`user_id` ASC, `date_key` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '视频观看记录表' ROW_FORMAT = Dynamic;

