-- ----------------------------
-- Table structure for advn_withdraw_order_2027
-- ----------------------------
DROP TABLE IF EXISTS `advn_withdraw_order_2027`;
CREATE TABLE `advn_withdraw_order_2027`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `order_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提现订单号(唯一)',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `coin_amount` decimal(18, 2) UNSIGNED NOT NULL COMMENT '提现金币数量',
  `exchange_rate` decimal(10, 4) UNSIGNED NULL DEFAULT 10000.0000 COMMENT '兑换比例',
  `cash_amount` decimal(10, 4) UNSIGNED NOT NULL COMMENT '提现金额(元)',
  `fee_amount` decimal(10, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '手续费(元)',
  `actual_amount` decimal(10, 4) UNSIGNED NOT NULL COMMENT '实际到账金额(元)',
  `withdraw_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提现方式: alipay/wechat/bank',
  `withdraw_account` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '提现账号',
  `withdraw_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '收款人姓名',
  `bank_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '银行名称(银行卡提现)',
  `bank_branch` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '开户行',
  `status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '状态: 0=待审核, 1=审核通过, 2=打款中, 3=提现成功, 4=审核拒绝, 5=打款失败, 6=已取消',
  `audit_type` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '审核类型: 0=自动审核, 1=人工审核',
  `audit_admin_id` int UNSIGNED NULL DEFAULT NULL COMMENT '审核管理员ID',
  `audit_admin_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核管理员名称',
  `audit_time` int UNSIGNED NULL DEFAULT NULL COMMENT '审核时间',
  `audit_remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '审核备注',
  `reject_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '拒绝原因',
  `transfer_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '打款流水号',
  `transfer_time` int UNSIGNED NULL DEFAULT NULL COMMENT '打款时间',
  `transfer_result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '打款结果(JSON)',
  `fail_reason` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '失败原因',
  `retry_count` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '重试次数',
  `next_retry_time` int UNSIGNED NULL DEFAULT NULL COMMENT '下次重试时间',
  `risk_score` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '风控评分(0-100)',
  `risk_tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '风控标签(JSON)',
  `commission_status` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '佣金发放状态: 0=未发放, 1=已发放',
  `commission_time` int UNSIGNED NULL DEFAULT NULL COMMENT '佣金发放时间',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '申请IP',
  `device_id` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备ID',
  `user_agent` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '用户UA',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间戳',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间戳',
  `complete_time` int UNSIGNED NULL DEFAULT NULL COMMENT '完成时间戳',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_no`(`order_no` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE,
  INDEX `idx_transfer_no`(`transfer_no` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '提现申请表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of advn_withdraw_order_2027
-- ----------------------------

-- ----------------------------
-- Table structure for advn_withdraw_risk_log
-- ----------------------------
DROP TABLE IF EXISTS `advn_withdraw_risk_log`;
CREATE TABLE `advn_withdraw_risk_log`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '记录ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `order_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '提现订单号',
  `risk_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '风险类型',
  `risk_level` tinyint UNSIGNED NULL DEFAULT 1 COMMENT '风险等级: 1=低, 2=中, 3=高',
  `risk_score` tinyint UNSIGNED NULL DEFAULT 0 COMMENT '风险评分(0-100)',
  `risk_detail` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '风险详情(JSON)',
  `handle_action` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '处理动作: pass/review/reject/freeze',
  `handle_remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '处理备注',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_order_no`(`order_no` ASC) USING BTREE,
  INDEX `idx_risk_type`(`risk_type` ASC) USING BTREE,
  INDEX `idx_create_time`(`createtime` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 534 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '提现风控记录表' ROW_FORMAT = Dynamic;

