-- ----------------------------
-- Table structure for advn_withdraw_stat
-- ----------------------------
DROP TABLE IF EXISTS `advn_withdraw_stat`;
CREATE TABLE `advn_withdraw_stat`  (
  `id` int UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '统计ID',
  `user_id` int UNSIGNED NOT NULL COMMENT '用户ID',
  `total_withdraw_count` int UNSIGNED NULL DEFAULT 0 COMMENT '累计提现次数',
  `total_withdraw_amount` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '累计提现金额(元)',
  `total_withdraw_coin` decimal(18, 2) UNSIGNED NULL DEFAULT 0.00 COMMENT '累计提现金币',
  `total_fee_amount` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '累计手续费(元)',
  `success_count` int UNSIGNED NULL DEFAULT 0 COMMENT '成功次数',
  `fail_count` int UNSIGNED NULL DEFAULT 0 COMMENT '失败次数',
  `today_withdraw_count` int UNSIGNED NULL DEFAULT 0 COMMENT '今日提现次数',
  `today_withdraw_amount` decimal(12, 4) UNSIGNED NULL DEFAULT 0.0000 COMMENT '今日提现金额',
  `today_withdraw_date` date NULL DEFAULT NULL COMMENT '今日统计日期',
  `first_withdraw_time` int UNSIGNED NULL DEFAULT NULL COMMENT '首次提现时间',
  `last_withdraw_time` int UNSIGNED NULL DEFAULT NULL COMMENT '最后提现时间',
  `createtime` int UNSIGNED NULL DEFAULT NULL COMMENT '创建时间',
  `updatetime` int UNSIGNED NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id`(`user_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 21 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '提现统计表' ROW_FORMAT = Dynamic;

